import React from "react";

type Status = "Active" | "Pending" | "Inactive";

interface BadgeProps {
  label: Status;
}

const colorMap: Record<Status, { background: string; color: string }> = {
  Active: { background: "#d1fae5", color: "#065f46" },
  Pending: { background: "#fef9c3", color: "#713f12" },
  Inactive: { background: "#fee2e2", color: "#991b1b" },
};

const Badge: React.FC<BadgeProps> = ({ label }) => {
  const colors = colorMap[label];
  return (
    <span
      style={{
        display: "inline-block",
        padding: "4px 12px",
        borderRadius: "9999px",
        fontSize: "14px",
        fontWeight: 600,
        backgroundColor: colors.background,
        color: colors.color,
      }}
    >
      {label}
    </span>
  );
};

const StatusBadges: React.FC = () => {
  const statuses: Status[] = ["Active", "Pending", "Inactive"];
  return (
    <div style={{ display: "flex", gap: "12px", alignItems: "center" }}>
      {statuses.map((status) => (
        <Badge key={status} label={status} />
      ))}
    </div>
  );
};

export default StatusBadges;

