import { useState } from "react";

interface UserProfileCardProps {
  avatarUrl?: string;
  name: string;
  bio: string;
  initialFollowing?: boolean;
  onFollowChange?: (following: boolean) => void;
}

export function UserProfileCard({
  avatarUrl,
  name,
  bio,
  initialFollowing = false,
  onFollowChange,
}: UserProfileCardProps) {
  const [following, setFollowing] = useState(initialFollowing);

  const handleFollow = () => {
    const next = !following;
    setFollowing(next);
    onFollowChange?.(next);
  };

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: "12px",
        padding: "24px",
        borderRadius: "12px",
        border: "1px solid #e5e7eb",
        boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
        maxWidth: "320px",
        fontFamily: "sans-serif",
        background: "#fff",
      }}
    >
      <img
        src={avatarUrl ?? `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&size=96`}
        alt={`${name} avatar`}
        style={{
          width: "96px",
          height: "96px",
          borderRadius: "50%",
          objectFit: "cover",
          border: "3px solid #e5e7eb",
        }}
      />
      <div style={{ textAlign: "center" }}>
        <h2 style={{ margin: "0 0 4px", fontSize: "1.2rem", fontWeight: 700, color: "#111827" }}>
          {name}
        </h2>
        <p style={{ margin: 0, fontSize: "0.9rem", color: "#6b7280", lineHeight: 1.5 }}>
          {bio}
        </p>
      </div>
      <button
        onClick={handleFollow}
        style={{
          marginTop: "4px",
          padding: "8px 28px",
          borderRadius: "9999px",
          border: following ? "1.5px solid #6b7280" : "none",
          background: following ? "#fff" : "#2563eb",
          color: following ? "#374151" : "#fff",
          fontWeight: 600,
          fontSize: "0.9rem",
          cursor: "pointer",
          transition: "all 0.15s",
        }}
      >
        {following ? "Following" : "Follow"}
      </button>
    </div>
  );
}

