import { useState } from "react";

interface ErrorAlertProps {
  message: string;
}

export function ErrorAlert({ message }: ErrorAlertProps) {
  const [visible, setVisible] = useState(true);

  if (!visible) return null;

  return (
    <div
      role="alert"
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "12px 16px",
        backgroundColor: "#fef2f2",
        border: "1px solid #fca5a5",
        borderRadius: "6px",
        color: "#b91c1c",
      }}
    >
      <span>{message}</span>
      <button
        onClick={() => setVisible(false)}
        aria-label="Dismiss"
        style={{
          background: "none",
          border: "none",
          cursor: "pointer",
          fontSize: "18px",
          lineHeight: 1,
          color: "#b91c1c",
          marginLeft: "12px",
          padding: "0 4px",
        }}
      >
        &times;
      </button>
    </div>
  );
}

