import { type DomphyElement } from "@domphy/core";
import { createForm } from "@domphy/form/domphy";
import { themeApply } from "@domphy/theme";
import { themeSpacing } from "@domphy/theme";
import { button, heading, inputText, label, paragraph } from "@domphy/ui";

themeApply();

const login = createForm<{ email: string; password: string }>({
  defaultValues: { email: "", password: "" },
  onSubmit: async ({ value }) => {
    await new Promise((r) => setTimeout(r, 800));
    console.log("submitted", value);
  },
});

const emailField = login.field<string>("email", {
  validators: {
    onChange: ({ value }: { value: string }) =>
      /^[^@]+@[^@]+\.[^@]+$/.test(value) ? undefined : "Enter a valid email",
  },
});

const passwordField = login.field<string>("password", {
  validators: {
    onChange: ({ value }: { value: string }) =>
      value.length >= 8 ? undefined : "At least 8 characters required",
  },
});

function fieldRow(
  labelText: string,
  inputType: string,
  inputId: string,
  handle: typeof emailField,
): DomphyElement<"div"> {
  return {
    div: [
      {
        label: labelText,
        htmlFor: inputId,
        $: [label()],
      },
      {
        input: null,
        id: inputId,
        type: inputType,
        placeholder: labelText,
        $: [inputText()],
        value: (l) => handle.value(l),
        onInput: (e) =>
          handle.handleChange((e.target as HTMLInputElement).value),
        onBlur: () => handle.handleBlur(),
      },
      {
        p: (l) => String(handle.errors(l)[0] ?? ""),
        $: [paragraph({ color: "error" })],
        dataSize: "decrease-1",
        hidden: (l) => handle.errors(l).length === 0,
      },
    ],
    style: {
      display: "flex",
      flexDirection: "column",
      gap: themeSpacing(1),
    },
  };
}

const App: DomphyElement<"div"> = {
  div: [
    {
      form: [
        { h2: "Sign in", $: [heading()] },
        fieldRow("Email", "email", "login-email", emailField),
        fieldRow("Password", "password", "login-password", passwordField),
        {
          button: (l) => (login.isSubmitting(l) ? "Signing in…" : "Sign in"),
          type: "submit",
          $: [button({ color: "primary" })],
          ariaDisabled: (l) => !login.canSubmit(l),
          style: { width: "100%" },
        },
