import { useState, useMemo } from "react";

const ITEMS = [
  "Apple",
  "Banana",
  "Cherry",
  "Date",
  "Elderberry",
  "Fig",
  "Grape",
  "Honeydew",
  "Kiwi",
  "Lemon",
  "Mango",
  "Nectarine",
  "Orange",
  "Papaya",
  "Quince",
  "Raspberry",
  "Strawberry",
  "Tangerine",
  "Ugli fruit",
  "Watermelon",
];

interface SearchBarProps {
  items?: string[];
  placeholder?: string;
}

export default function SearchBar({
  items = ITEMS,
  placeholder = "Search...",
}: SearchBarProps) {
  const [query, setQuery] = useState("");

  const filtered = useMemo(() => {
    const trimmed = query.trim().toLowerCase();
    if (!trimmed) return items;
    return items.filter((item) => item.toLowerCase().includes(trimmed));
  }, [query, items]);

  return (
    <div style={{ fontFamily: "sans-serif", maxWidth: 400, margin: "2rem auto" }}>
      <input
        type="search"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder={placeholder}
        aria-label="Search"
        style={{
          width: "100%",
          padding: "0.5rem 0.75rem",
          fontSize: "1rem",
          border: "1px solid #ccc",
          borderRadius: 6,
          boxSizing: "border-box",
          outline: "none",
        }}
      />
      <p style={{ margin: "0.5rem 0", fontSize: "0.85rem", color: "#666" }}>
        {filtered.length} result{filtered.length !== 1 ? "s" : ""}
      </p>
      <ul
        role="listbox"
        aria-label="Search results"
        style={{
          listStyle: "none",
          margin: 0,
          padding: 0,
          border: filtered.length ? "1px solid #e5e5e5" : "none",
          borderRadius: 6,
          overflow: "hidden",
        }}
      >
        {filtered.map((item) => (
          <li
            key={item}
            role="option"
            aria-selected={false}
            style={{
              padding: "0.5rem 0.75rem",
              borderBottom: "1px solid #f0f0f0",
              cursor: "default",
            }}
          >
            {item}
          </li>
        ))}
        {filtered.length === 0 && (
          <li style={{ padding: "0.5rem 0.75rem", color: "#999" }}>
            No results found.
          </li>
        )}
      </ul>
    </div>
  );
}

