import { useState, useMemo } from "react";

type SortDirection = "asc" | "desc";

interface User {
  name: string;
  email: string;
  role: string;
}

const initialData: User[] = [
  { name: "Charlie Brown", email: "charlie@example.com", role: "Admin" },
  { name: "Alice Smith", email: "alice@example.com", role: "Editor" },
  { name: "Eve Davis", email: "eve@example.com", role: "Viewer" },
  { name: "Bob Johnson", email: "bob@example.com", role: "Editor" },
  { name: "Diana Prince", email: "diana@example.com", role: "Admin" },
];

export default function DataTable() {
  const [sortDirection, setSortDirection] = useState<SortDirection>("asc");

  const sortedData = useMemo(() => {
    return [...initialData].sort((a, b) => {
      const comparison = a.name.localeCompare(b.name);
      return sortDirection === "asc" ? comparison : -comparison;
    });
  }, [sortDirection]);

  function toggleSort() {
    setSortDirection((previous) => (previous === "asc" ? "desc" : "asc"));
  }

  return (
    <table style={{ borderCollapse: "collapse", width: "100%", fontFamily: "sans-serif" }}>
      <thead>
        <tr style={{ backgroundColor: "#f0f0f0" }}>
          <th
            onClick={toggleSort}
            style={{ padding: "10px 16px", textAlign: "left", cursor: "pointer", userSelect: "none", borderBottom: "2px solid #ccc" }}
          >
            Name {sortDirection === "asc" ? "▲" : "▼"}
          </th>
          <th style={{ padding: "10px 16px", textAlign: "left", borderBottom: "2px solid #ccc" }}>Email</th>
          <th style={{ padding: "10px 16px", textAlign: "left", borderBottom: "2px solid #ccc" }}>Role</th>
        </tr>
      </thead>
      <tbody>
        {sortedData.map((user) => (
          <tr key={user.email} style={{ borderBottom: "1px solid #eee" }}>
            <td style={{ padding: "10px 16px" }}>{user.name}</td>
            <td style={{ padding: "10px 16px" }}>{user.email}</td>
            <td style={{ padding: "10px 16px" }}>{user.role}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

