import { useState } from "react";

interface ConfirmDialogProps {
  open: boolean;
  onCancel: () => void;
  onConfirm: () => void;
}

function ConfirmDialog({ open, onCancel, onConfirm }: ConfirmDialogProps) {
  if (!open) return null;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        backgroundColor: "rgba(0,0,0,0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 1000,
      }}
      onClick={onCancel}
    >
      <div
        style={{
          background: "#fff",
          borderRadius: 8,
          padding: "24px 32px",
          minWidth: 320,
          boxShadow: "0 4px 24px rgba(0,0,0,0.18)",
        }}
        onClick={(e) => e.stopPropagation()}
      >
        <h2 style={{ margin: "0 0 8px", fontSize: 18, fontWeight: 600 }}>
          Confirm Delete
        </h2>
        <p style={{ margin: "0 0 24px", color: "#555" }}>
          Are you sure you want to delete this item? This action cannot be undone.
        </p>
        <div style={{ display: "flex", justifyContent: "flex-end", gap: 12 }}>
          <button
            onClick={onCancel}
            style={{
              padding: "8px 20px",
              borderRadius: 6,
              border: "1px solid #d1d5db",
              background: "#fff",
              cursor: "pointer",
              fontSize: 14,
            }}
          >
            Cancel
          </button>
          <button
            onClick={onConfirm}
            style={{
              padding: "8px 20px",
              borderRadius: 6,
              border: "none",
              background: "#dc2626",
              color: "#fff",
              cursor: "pointer",
              fontSize: 14,
              fontWeight: 600,
            }}
          >
            Confirm Delete
          </button>
        </div>
      </div>
    </div>
  );
}

export default function Page() {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [deleted, setDeleted] = useState(false);

  function handleConfirm() {
    setDeleted(true);
    setDialogOpen(false);
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        fontFamily: "sans-serif",
        gap: 16,
      }}
    >
      {deleted ? (
        <p style={{ color: "#16a34a", fontWeight: 600 }}>Item deleted.</p>
      ) : (
        <button
          onClick={() => setDialogOpen(true)}
          style={{
            padding: "10px 24px",
            borderRadius: 6,
            border: "none",
            background: "#dc2626",
            color: "#fff",
            cursor: "pointer",
            fontSize: 15,
            fontWeight: 600,
          }}
        >
          Delete Item
        </button>
      )}

      <ConfirmDialog
        open={dialogOpen}
        onCancel={() => setDialogOpen(false)}
        onConfirm={handleConfirm}
      />
    </div>
  );
}

