import { ElementNode, RecordState, effect, toState } from "@domphy/core";
import { themeApply, themeSpacing } from "@domphy/theme";
import { button, toast } from "@domphy/ui";

themeApply();

// Each toast entry: id + message
interface ToastEntry {
  id: number;
  message: string;
}

// RecordState holds the current toast list
const toastStore = new RecordState({
  list: [] as ToastEntry[],
  nextId: 0,
});

function addToast(message: string): void {
  const id = toastStore.get("nextId");
  toastStore.set("nextId", id + 1);
  toastStore.set("list", [...toastStore.get("list"), { id, message }]);
}

function removeToast(id: number): void {
  toastStore.set(
    "list",
    toastStore.get("list").filter((entry) => entry.id !== id),
  );
}

// effect() watches the toast list and schedules auto-dismiss timers.
// Each time the list changes, we only schedule a timer for entries
// that do not already have one (tracked via a Set of seen ids).
const scheduledIds = new Set<number>();

effect(() => {
  const list = toastStore.get("list");
  for (const entry of list) {
    if (!scheduledIds.has(entry.id)) {
      scheduledIds.add(entry.id);
      setTimeout(() => {
        removeToast(entry.id);
        scheduledIds.delete(entry.id);
      }, 3000);
    }
  }
});

