  style: {
    display: "flex",
    flexDirection: "column",
    alignItems: "start",
    gap: themeSpacing(4),
    padding: themeSpacing(6),
  },
};

new ElementNode(App).render(document.getElementById("app")!);

import type { DomphyElement, ElementNode } from "@domphy/core";
import { ElementNode as EN, RecordState, effect, toState } from "@domphy/core";
import { themeApply } from "@domphy/theme";
import { themeSpacing } from "@domphy/theme";
import { button, toast } from "@domphy/ui";

themeApply();

// Each entry: { id, message, node }
type ToastEntry = {
  id: number;
  message: string;
  node: ElementNode | null;
};

const toastList = new RecordState<{
  entries: ToastEntry[];
  counter: number;
}>({
  entries: [],
  counter: 0,
});

function addToast(rootNode: ElementNode, message: string): void {
  const id = toastList.get("counter") + 1;
  toastList.set("counter", id);

  const entry: ToastEntry = { id, message, node: null };
  toastList.set("entries", [...toastList.get("entries"), entry]);

  const toastEle: DomphyElement<"div"> = {
    div: message,
    $: [toast({ position: "top-right", color: "neutral" })],
  };

  const toastNode = rootNode.children.insert(toastEle) as ElementNode;
  entry.node = toastNode;

  // effect() watches the entry list; when this id is still present we schedule
  // auto-dismiss after 3 seconds using a one-shot timer.
  const active = toState(true);

  const releaseEffect = effect(() => {
    if (!active.get()) return;
    const timer = setTimeout(() => {
      active.set(false);
      releaseEffect();
      const remaining = toastList
        .get("entries")
        .filter((e) => e.id !== id);
      toastList.set("entries", remaining);
      toastNode.remove();
    }, 3000);
    return () => clearTimeout(timer);
  });
}

const App: DomphyElement<"div"> = {
  div: [
    {
      div: (l) => {
        const entries = toastList.get("entries", l);
        if (entries.length === 0) return "No active toasts.";
        return `Active toasts: ${entries.map((e) => e.message).join(", ")}`;
      },
    },
    {
      button: "Show Toast",
      $: [button({ color: "primary" })],
      onClick: (_e, node) => {
        const messages = [
          "Saved successfully",
          "Changes applied",
          "Upload complete",
          "Action done",
        ];
        const message =
          messages[toastList.get("counter") % messages.length];
        addToast(node.getRoot(), message);
      },
    },
  ],
  dataTheme: "light",
  style: {
    display: "flex",
    flexDirection: "column",
    alignItems: "start",
    gap: themeSpacing(4),
    padding: themeSpacing(8),
  },
};

new EN(App).render(document.getElementById("app")!);

import type { DomphyElement, ElementNode } from "@domphy/core";
import { RecordState, effect } from "@domphy/core";
import { themeApply, themeSpacing } from "@domphy/theme";
import { button, toast } from "@domphy/ui";

themeApply();

type ToastItem = { id: string; message: string };

const toastState = new RecordState({ list: [] as ToastItem[] });

let appNode: ElementNode | null = null;
const scheduled = new Set<string>();

effect(() => {
  const list = toastState.get("list");
  if (!appNode) return;

  for (const item of list) {
    if (scheduled.has(item.id)) continue;
    scheduled.add(item.id);

    const toastElement: DomphyElement<"div"> = {
      div: item.message,
      $: [toast({ position: "top-right", color: "neutral" })],
    };

    const toastNode = appNode.getRoot().children.insert(toastElement) as ElementNode;

    setTimeout(() => {
      toastNode.remove();
      toastState.set("list", toastState.get("list").filter((t) => t.id !== item.id));
      scheduled.delete(item.id);
    }, 3000);
  }
});

let counter = 0;

function addToast(message: string): void {
  counter++;
  const item: ToastItem = { id: `toast-${counter}`, message };
  toastState.set("list", [...toastState.get("list"), item]);
}

const App: DomphyElement<"div"> = {
  div: [
    {
      button: "Show Toast",
      $: [button({ color: "primary" })],
      onClick: () => addToast(`Notification #${counter + 1}`),
    },
  ],
  dataTheme: "light",
  style: {
    display: "flex",
    flexDirection: "column",
    alignItems: "start",
    gap: themeSpacing(4),
    padding: themeSpacing(6),
  },
  _onMount: (node) => {
    appNode = node;
  },
};

new ElementNode(App).render(document.getElementById("app")!);

import { useState, useEffect, useCallback } from "react";

interface Toast {
  id: number;
  message: string;
  type?: "info" | "success" | "error" | "warning";
}

interface ToastItemProps {
  toast: Toast;
  onDismiss: (id: number) => void;
}

function ToastItem({ toast, onDismiss }: ToastItemProps) {
  useEffect(() => {
    const timer = setTimeout(() => {
      onDismiss(toast.id);
    }, 3000);
    return () => clearTimeout(timer);
  }, [toast.id, onDismiss]);

  const colors: Record<NonNullable<Toast["type"]>, string> = {
    info: "#2196F3",
    success: "#4CAF50",
    error: "#F44336",
    warning: "#FF9800",
  };

  const background = colors[toast.type ?? "info"];

  return (
    <div
      style={{
        background,
        color: "#fff",
        padding: "12px 20px",
        borderRadius: "6px",
        marginBottom: "8px",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        minWidth: "280px",
        boxShadow: "0 2px 8px rgba(0,0,0,0.2)",
        animation: "slideIn 0.3s ease",
      }}
    >
      <span>{toast.message}</span>
      <button
        onClick={() => onDismiss(toast.id)}
        style={{
          background: "none",
          border: "none",
          color: "#fff",
          cursor: "pointer",
          fontSize: "18px",
          marginLeft: "12px",
          lineHeight: 1,
        }}
        aria-label="Dismiss"
      >
        ×
      </button>
    </div>
  );
}

interface ToastContainerProps {
  toasts: Toast[];
  onDismiss: (id: number) => void;
}

function ToastContainer({ toasts, onDismiss }: ToastContainerProps) {
  return (
    <div
      style={{
        position: "fixed",
        bottom: "24px",
        right: "24px",
        zIndex: 9999,
      }}
    >
      <style>{`
        @keyframes slideIn {
          from { transform: translateX(100%); opacity: 0; }
          to { transform: translateX(0); opacity: 1; }
        }
      `}</style>
      {toasts.map((toast) => (
        <ToastItem key={toast.id} toast={toast} onDismiss={onDismiss} />
      ))}
    </div>
  );
}

let nextId = 1;

export default function App() {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const dismiss = useCallback((id: number) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  const addToast = useCallback(
    (message: string, type: Toast["type"] = "info") => {
      const id = nextId++;
      setToasts((prev) => [...prev, { id, message, type }]);
    },
    []
  );

  return (
    <div style={{ padding: "40px", fontFamily: "sans-serif" }}>
      <h1>Toast Notification Demo</h1>
      <div style={{ display: "flex", gap: "12px", flexWrap: "wrap" }}>
        <button onClick={() => addToast("This is an info message.", "info")}>
          Info Toast
        </button>
        <button
          onClick={() => addToast("Operation completed successfully!", "success")}
        >
          Success Toast
        </button>
        <button onClick={() => addToast("Something went wrong.", "error")}>
          Error Toast
        </button>
        <button
          onClick={() => addToast("Please review your input.", "warning")}
        >
          Warning Toast
        </button>
      </div>
      <ToastContainer toasts={toasts} onDismiss={dismiss} />
    </div>
  );
}

