import { computed, ElementNode, toState } from "@domphy/core";
import { themeApply, themeSpacing } from "@domphy/theme";
import {
  button,
  command,
  commandItem,
  dialog,
  inputSearch,
} from "@domphy/ui";

themeApply();

// --- Static command definitions ---

interface Command {
  id: string;
  label: string;
  action: () => void;
}

const COMMANDS: Command[] = [
  { id: "new-file",      label: "New File",         action: () => console.log("New File") },
  { id: "open-file",     label: "Open File…",        action: () => console.log("Open File") },
  { id: "save-file",     label: "Save",              action: () => console.log("Save") },
  { id: "save-as",       label: "Save As…",          action: () => console.log("Save As") },
  { id: "close-file",    label: "Close Editor",      action: () => console.log("Close Editor") },
  { id: "run-tests",     label: "Run Tests",         action: () => console.log("Run Tests") },
  { id: "open-terminal", label: "Open Terminal",     action: () => console.log("Open Terminal") },
  { id: "format-doc",    label: "Format Document",   action: () => console.log("Format Document") },
  { id: "go-to-line",    label: "Go to Line…",       action: () => console.log("Go to Line") },
  { id: "command-log",   label: "Show Command Log",  action: () => console.log("Show Command Log") },
];

// --- Reactive state ---

const isOpen = toState(false);
const query = toState("");
const selectedIndex = toState(-1);

// Derived filtered list via computed() — re-evaluates whenever query changes.
// query.get() inside the fn is auto-tracked as a dependency.
const filtered = computed<Command[]>(() => {
  const q = query.get().trim().toLowerCase();
  if (!q) return COMMANDS;
  return COMMANDS.filter((cmd) => cmd.label.toLowerCase().includes(q));
});

// --- Helpers ---

function openPalette(): void {
  query.set("");
  selectedIndex.set(-1);
  isOpen.set(true);
}

function closePalette(): void {
  isOpen.set(false);
}

function runSelected(): void {
  const index = selectedIndex.get();
  const list = filtered.get();
  if (index >= 0 && index < list.length) {
    list[index].action();
    closePalette();
  }
}

function moveSelection(delta: number): void {
  const list = filtered.get();
  const current = selectedIndex.get();
  const next = Math.max(-1, Math.min(list.length - 1, current + delta));
  selectedIndex.set(next);
}

// --- Global keydown handler for Cmd+K / Ctrl+K ---

document.addEventListener("keydown", (e: KeyboardEvent) => {
  if ((e.metaKey || e.ctrlKey) && e.key === "k") {
    e.preventDefault();
    if (isOpen.get()) {
      closePalette();
    } else {
      openPalette();
    }
    return;
  }

  if (!isOpen.get()) return;

  if (e.key === "Escape") {
    e.preventDefault();
    closePalette();
    return;
  }

  if (e.key === "ArrowDown") {
    e.preventDefault();
    moveSelection(1);
    return;
  }

  if (e.key === "ArrowUp") {
    e.preventDefault();
    moveSelection(-1);
    return;
  }

  if (e.key === "Enter") {
    e.preventDefault();
    runSelected();
  }
});

// --- App element ---

const App = {
  div: [
    {
      p: "Press Cmd+K (or Ctrl+K) to open the command palette.",
      style: {
        fontFamily: "inherit",
        padding: themeSpacing(4),
