    {
      dialog: [
        {
          div: [
            // Search input — uses inputSearch() patch; value/onInput wired to query state.
            {
              input: null,
              placeholder: "Search commands…",
              value: (l) => query.get(l),
              onInput: (e) => {
                query.set((e.target as HTMLInputElement).value);
                selectedIndex.set(-1);
              },
              onKeyDown: (e) => {
                // Prevent dialog from catching arrow/enter keys handled globally.
                if (["ArrowDown", "ArrowUp", "Enter", "Escape"].includes(e.key)) {
                  e.stopPropagation();
                }
              },
              $: [inputSearch({ color: "neutral", accentColor: "primary" })],
              style: {
                width: "100%",
                boxSizing: "border-box",
              },
            },
            // Reactive command list from filtered computed.
            {
              div: (l) =>
                filtered.get(l).map((cmd, index) => ({
                  button: cmd.label,
