                  $: [commandItem({ color: "neutral", accentColor: "primary" })],
                  dataSelected: (listener) =>
                    selectedIndex.get(listener) === index ? "true" : undefined,
                  onClick: () => {
                    cmd.action();
                    closePalette();
                  },
                  style: {
                    fontWeight: (listener) =>
                      selectedIndex.get(listener) === index ? "bold" : "normal",
                    backgroundColor: (listener) =>
                      selectedIndex.get(listener) === index
