                        : "none",
                    outlineOffset: "-2px",
                  },
                })),
              $: [command()],
              style: {
                maxHeight: themeSpacing(60),
                overflowY: "auto",
              },
            },
          ],
          style: {
            display: "flex",
            flexDirection: "column",
            gap: "0",
            width: themeSpacing(80),
            padding: "0",
          },
        },
      ],
      $: [dialog({ open: isOpen })],
      style: {
        width: themeSpacing(80),
        padding: "0",
