  { id: "save-as",     label: "Save As...",         description: "Save file with a new name",      action: () => console.log("Save As") },
  { id: "close-file",  label: "Close File",         description: "Close the current file",         action: () => console.log("Close File") },
  { id: "find",        label: "Find",               description: "Search within the current file", action: () => console.log("Find") },
  { id: "replace",     label: "Find & Replace",     description: "Find and replace text",          action: () => console.log("Find & Replace") },
  { id: "toggle-term", label: "Toggle Terminal",    description: "Show or hide the terminal",      action: () => console.log("Toggle Terminal") },
  { id: "settings",    label: "Open Settings",      description: "Open user settings",             action: () => console.log("Settings") },
  { id: "theme",       label: "Change Theme",       description: "Switch the color theme",         action: () => console.log("Change Theme") },
];

// ---------------------------------------------------------------------------
// State
// ---------------------------------------------------------------------------

const isOpen    = toState(false);
const query     = toState("");
const selection = toState(0);

// Filtered list — recomputed whenever query changes.
const filteredItems = computed<Command[]>(() => {
  const q = query.get();
  if (!q) return ALL_COMMANDS;
  const lower = q.toLowerCase();
  return ALL_COMMANDS.filter(
    (c) =>
      c.label.toLowerCase().includes(lower) ||
      c.description.toLowerCase().includes(lower),
  );
});

// Clamp selection when filtered list shrinks.
filteredItems.addListener(() => {
  const max = Math.max(filteredItems.get().length - 1, 0);
  if (selection.get() > max) selection.set(max);
});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function openPalette(): void {
  query.set("");
  selection.set(0);
  isOpen.set(true);
}

function closePalette(): void {
  isOpen.set(false);
}

function runSelected(): void {
  const items = filteredItems.get();
  const item  = items[selection.get()];
  if (item) {
    item.action();
    closePalette();
  }
}

function moveSelection(delta: number): void {
  const count = filteredItems.get().length;
  if (count === 0) return;
  selection.set((selection.get() + delta + count) % count);
}

// ---------------------------------------------------------------------------
// Command-palette dialog content
// ---------------------------------------------------------------------------

function CommandItem(item: Command, index: number): DomphyElement<"button"> {
  return {
    button: [
      { span: item.label, $: [small()] },
      " ",
      { span: item.description },
    ],
    _key: item.id,
    ariaSelected: (l) => String(selection.get(l) === index),
    onClick: () => {
      item.action();
      closePalette();
    },
    style: {
      fontStyle: (l) =>
        selection.get(l) === index ? "normal" : "normal",
      // Highlight selected row via a data attribute drive from selection state.
      backgroundColor: (l) =>
        selection.get(l) === index ? "var(--dp-accent-selected)" : "",
    },
    $: [commandItem({ color: "neutral", accentColor: "primary" })],
  };
}

// Dialog inner content — a command() container with search + list.
const PaletteContent: DomphyElement<"div"> = {
  div: [
    // Search input — commandSearch wires into command() context automatically.
    {
      input: null,
      placeholder: "Type a command…",
      ariaLabel: "Command search",
      value:   (l) => query.get(l),
      onInput: (e) => {
        query.set((e.target as HTMLInputElement).value);
        selection.set(0);
      },
      onKeyDown: (e) => {
        const key = (e as KeyboardEvent).key;
        if (key === "ArrowDown") { e.preventDefault(); moveSelection(1);   }
        if (key === "ArrowUp")   { e.preventDefault(); moveSelection(-1);  }
        if (key === "Enter")     { e.preventDefault(); runSelected();      }
        if (key === "Escape")    { e.preventDefault(); closePalette();     }
      },
      $: [commandSearch({ color: "neutral", accentColor: "primary" })],
    },
    // Filtered items list — reactive via computed().
    {
      div: (l) => {
        const items = filteredItems.get(l);
        if (items.length === 0) {
          return [{ p: "No commands match your search." }];
        }
        return items.map((item, index) => CommandItem(item, index));
      },
      role: "listbox",
      ariaLabel: "Commands",
      style: {
        overflowY: "auto",
        maxHeight: "320px",
      },
    },
  ],
  $: [command()],
};

// The modal dialog element.
const PaletteDialog: DomphyElement<"dialog"> = {
  dialog: [
    { h2: "Command Palette", $: [heading({ color: "neutral" })] },
    PaletteContent,
  ],
  ariaLabel: "Command palette",
  $: [dialog({ color: "neutral", open: isOpen })],
  style: {
    minWidth: "480px",
    maxWidth: "600px",
    width: "100%",
    borderRadius: "8px",
  },
};

// ---------------------------------------------------------------------------
// App shell
// ---------------------------------------------------------------------------

const App: DomphyElement<"div"> = {
  div: [
    PaletteDialog,
    {
      p: [
        "Press ",
        { kbd: "Ctrl + K", $: [] },
        " to open the command palette.",
      ],
    },
  ],
  dataTheme: "light",
  _onMount: (node) => {
    const handler = (e: Event) => {
      const ke = e as KeyboardEvent;
      if ((ke.ctrlKey || ke.metaKey) && ke.key === "k") {
        ke.preventDefault();
        if (isOpen.get()) {
          closePalette();
        } else {
          openPalette();
        }
      }
    };
    document.addEventListener("keydown", handler);
    node.addHook("Remove", () => document.removeEventListener("keydown", handler));
  },
};

// ---------------------------------------------------------------------------
// Mount
// ---------------------------------------------------------------------------

new ElementNode(App).render(document.getElementById("app")!);

import React, { useState, useEffect, useMemo, useRef } from "react";

const COMMANDS = [
  { id: 1, label: "Open File", description: "Open a file from disk" },
  { id: 2, label: "Save File", description: "Save the current file" },
  { id: 3, label: "Close Tab", description: "Close the current tab" },
  { id: 4, label: "New Terminal", description: "Open a new terminal window" },
  { id: 5, label: "Toggle Sidebar", description: "Show or hide the sidebar" },
  { id: 6, label: "Go to Line", description: "Navigate to a specific line" },
  { id: 7, label: "Find in Files", description: "Search across all files" },
  { id: 8, label: "Format Document", description: "Run the code formatter" },
  { id: 9, label: "Toggle Theme", description: "Switch between light and dark mode" },
  { id: 10, label: "Open Settings", description: "Open the settings panel" },
];

interface Command {
  id: number;
  label: string;
  description: string;
}

const CommandPalette: React.FC = () => {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const [activeIndex, setActiveIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLUListElement>(null);

  const filtered = useMemo<Command[]>(() => {
    const lower = query.toLowerCase();
    return COMMANDS.filter(
      (command) =>
        command.label.toLowerCase().includes(lower) ||
        command.description.toLowerCase().includes(lower)
    );
  }, [query]);

  useEffect(() => {
    setActiveIndex(0);
  }, [filtered]);

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if ((event.metaKey || event.ctrlKey) && event.key === "k") {
        event.preventDefault();
        setOpen((previous) => !previous);
      }
      if (event.key === "Escape") {
        setOpen(false);
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, []);

  useEffect(() => {
    if (open) {
      setQuery("");
      setActiveIndex(0);
      setTimeout(() => inputRef.current?.focus(), 0);
    }
  }, [open]);

  useEffect(() => {
    if (!listRef.current) return;
    const item = listRef.current.children[activeIndex] as HTMLElement | undefined;
    item?.scrollIntoView({ block: "nearest" });
  }, [activeIndex]);

  const handleKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === "ArrowDown") {
      event.preventDefault();
      setActiveIndex((previous) => Math.min(previous + 1, filtered.length - 1));
    } else if (event.key === "ArrowUp") {
      event.preventDefault();
      setActiveIndex((previous) => Math.max(previous - 1, 0));
    } else if (event.key === "Enter") {
      const selected = filtered[activeIndex];
      if (selected) {
        alert(`Executed: ${selected.label}`);
        setOpen(false);
      }
    }
  };

  const handleSelect = (command: Command) => {
    alert(`Executed: ${command.label}`);
    setOpen(false);
  };

  if (!open) {
    return (
      <div style={{ padding: "2rem", fontFamily: "sans-serif" }}>
        <p>Press <kbd style={kbdStyle}>Ctrl+K</kbd> / <kbd style={kbdStyle}>Cmd+K</kbd> to open the command palette.</p>
      </div>
    );
  }

  return (
    <div style={overlayStyle} onClick={() => setOpen(false)}>
      <div style={paletteStyle} onClick={(e) => e.stopPropagation()}>
        <input
          ref={inputRef}
          style={inputStyle}
          type="text"
          placeholder="Search commands..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        {filtered.length > 0 ? (
          <ul ref={listRef} style={listStyle}>
            {filtered.map((command, index) => (
              <li
                key={command.id}
                style={{
                  ...itemStyle,
                  backgroundColor: index === activeIndex ? "#3b82f6" : "transparent",
                  color: index === activeIndex ? "#fff" : "#1f2937",
                }}
                onMouseEnter={() => setActiveIndex(index)}
                onClick={() => handleSelect(command)}
              >
                <span style={labelStyle}>{command.label}</span>
                <span
                  style={{
                    ...descStyle,
                    color: index === activeIndex ? "#dbeafe" : "#6b7280",
                  }}
                >
                  {command.description}
                </span>
              </li>
            ))}
          </ul>
        ) : (
          <p style={emptyStyle}>No commands found.</p>
        )}
        <div style={footerStyle}>
          <span><kbd style={kbdStyle}>↑↓</kbd> navigate</span>
          <span><kbd style={kbdStyle}>Enter</kbd> select</span>
          <span><kbd style={kbdStyle}>Esc</kbd> close</span>
        </div>
      </div>
    </div>
  );
};

const overlayStyle: React.CSSProperties = {
  position: "fixed",
  inset: 0,
  backgroundColor: "rgba(0,0,0,0.5)",
  display: "flex",
  alignItems: "flex-start",
