themeApply();

// ─── State ───────────────────────────────────────────────────────────────────

const TOTAL_STEPS = 3;

interface WizardData {
  name: string;
  email: string;
  theme: string;
  language: string;
}

const step = toState(1);

const form = createForm<WizardData>({
  defaultValues: {
    name: "",
    email: "",
    theme: "light",
    language: "en",
  },
  onSubmit: async ({ value }) => {
    // Replace with real submit logic
    console.log("Submitted:", value);
    alert(`Submitted!\n${JSON.stringify(value, null, 2)}`);
  },
});

const nameHandle = form.field<string>("name", {
  validators: {
    onChange: ({ value }: { value: string }) =>
      !value.trim() ? { onChange: "Name is required" } : undefined,
  },
});

const emailHandle = form.field<string>("email", {
  validators: {
    onChange: ({ value }: { value: string }) =>
      !value.trim()
        ? { onChange: "Email is required" }
        : !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)
          ? { onChange: "Enter a valid email" }
          : undefined,
  },
});

const themeHandle = form.field<string>("theme");
const languageHandle = form.field<string>("language");

// ─── Helpers ─────────────────────────────────────────────────────────────────

function goNext(): void {
  step.set(step.get() + 1);
}

function goBack(): void {
  step.set(step.get() - 1);
}

function fieldError(errors: unknown[]): DomphyElement<"span"> | null {
  if (!errors.length) return null;
  return {
    span: String(errors[0]),
    $: [small({ color: "error" })],
    style: { display: "block", marginTop: themeSpacing(1) },
  };
}

// ─── Progress indicator ───────────────────────────────────────────────────────

const ProgressBar: DomphyElement<"div"> = {
  div: [
    {
      div: [
        {
          span: (l) => `Step ${step.get(l)} of ${TOTAL_STEPS}`,
          $: [small()],
        },
      ],
      style: {
        display: "flex",
        justifyContent: "space-between",
        marginBottom: themeSpacing(2),
      },
    },
    {
      progress: null,
      max: TOTAL_STEPS,
      value: (l) => step.get(l),
      $: [progress({ accentColor: "primary" })],
      style: { width: "100%" },
    },
  ],
  style: { marginBottom: themeSpacing(6) },
};

// ─── Step 1 — Name & Email ────────────────────────────────────────────────────

function Step1(): DomphyElement<"div"> {
  return {
    div: [
      {
        h2: "Personal Information",
        $: [heading()],
        style: { marginBottom: themeSpacing(6) },
      },
      // Name field
      {
        div: [
          {
            label: "Full Name",
            $: [label()],
            htmlFor: "wizard-name",
          },
          {
            input: null,
            id: "wizard-name",
            type: "text",
            placeholder: "Enter your full name",
