            onInput: (e) => {
              nameHandle.handleChange(
                (e.target as HTMLInputElement).value,
              );
            },
            onBlur: () => nameHandle.handleBlur(),
            $: [inputText()],
            style: { width: "100%" },
          },
          {
            div: (l) => {
              const errors = nameHandle.errors(l) as unknown[];
              const err = fieldError(errors);
              return err ? [err] : [];
            },
          },
        ],
        style: {
          display: "flex",
          flexDirection: "column",
          gap: themeSpacing(2),
          marginBottom: themeSpacing(4),
        },
      },
      // Email field
      {
        div: [
          {
            label: "Email Address",
            $: [label()],
            htmlFor: "wizard-email",
          },
          {
            input: null,
            id: "wizard-email",
            type: "email",
            placeholder: "Enter your email",
            value: (l) => emailHandle.value(l) as string,
            onInput: (e) => {
              emailHandle.handleChange(
                (e.target as HTMLInputElement).value,
              );
            },
            onBlur: () => emailHandle.handleBlur(),
            $: [inputText()],
            style: { width: "100%" },
          },
          {
            div: (l) => {
              const errors = emailHandle.errors(l) as unknown[];
              const err = fieldError(errors);
