  select,
  small,
} from "@domphy/ui";

themeApply();

// ── State ─────────────────────────────────────────────────────────────────────

const step = toState<1 | 2 | 3>(1);

// ── Form ──────────────────────────────────────────────────────────────────────

type WizardValues = {
  name: string;
  email: string;
  theme: string;
  language: string;
};

const form = createForm<WizardValues>({
  defaultValues: { name: "", email: "", theme: "light", language: "en" },
  onSubmit: async ({ value }) => {
    await new Promise<void>((r) => setTimeout(r, 600));
    console.log("Wizard submitted:", value);
    alert(`Submitted!\n${JSON.stringify(value, null, 2)}`);
  },
});

const nameField = form.field<string>("name", {
  validators: {
    onChange: ({ value }: { value: string }) =>
      value.trim().length >= 2 ? undefined : "Name must be at least 2 characters",
  },
});

const emailField = form.field<string>("email", {
  validators: {
    onChange: ({ value }: { value: string }) =>
      /^[^@]+@[^@]+\.[^@]+$/.test(value) ? undefined : "Enter a valid email address",
  },
});

const themeField = form.field<string>("theme");
const languageField = form.field<string>("language");

// ── Helpers ───────────────────────────────────────────────────────────────────

const STEP_TOTAL = 3;

const THEME_OPTIONS = [
  { label: "Light", value: "light" },
  { label: "Dark", value: "dark" },
  { label: "System", value: "system" },
];

const LANGUAGE_OPTIONS = [
  { label: "English", value: "en" },
  { label: "Vietnamese", value: "vi" },
  { label: "Japanese", value: "ja" },
  { label: "French", value: "fr" },
];

function fieldError(handle: typeof nameField): DomphyElement<"p"> {
  return {
    p: (l) => String(handle.errors(l)[0] ?? ""),
    $: [paragraph({ color: "error" })],
    dataSize: "decrease-1",
    hidden: (l) => handle.errors(l).length === 0,
  };
}

// ── Progress indicator ────────────────────────────────────────────────────────

function ProgressIndicator(): DomphyElement<"div"> {
  return {
    div: [
      {
        progress: null,
        max: STEP_TOTAL,
        value: (l) => step.get(l),
        $: [progress({ accentColor: "primary" })],
        style: { width: "100%" },
      },
      {
        div: [
          {
            span: (l) => `Step ${step.get(l)} of ${STEP_TOTAL}`,
            $: [small()],
          },
          {
            span: (l) => {
              const labels: Record<number, string> = {
                1: "Personal Info",
                2: "Preferences",
                3: "Review & Submit",
              };
              return labels[step.get(l)] ?? "";
            },
            $: [small()],
          },
        ],
        style: {
          display: "flex",
          justifyContent: "space-between",
          marginTop: themeSpacing(1),
        },
      },
    ],
    style: {
      display: "flex",
      flexDirection: "column",
      gap: themeSpacing(1),
      marginBottom: themeSpacing(4),
    },
  };
}

// ── Step 1: Name & Email ──────────────────────────────────────────────────────

function Step1(): DomphyElement<"div"> {
  return {
    div: [
      {
        h2: "Personal Information",
        $: [heading()],
        style: { marginBottom: themeSpacing(3) },
      },
      {
        fieldset: [
          { legend: "Contact details" },
          { label: "Full name", $: [label()] },
          {
            input: null,
            type: "text",
            placeholder: "Jane Doe",
            $: [inputText()],
            value: (l) => nameField.value(l),
            onInput: (e) =>
              nameField.handleChange((e.target as HTMLInputElement).value),
            onBlur: () => nameField.handleBlur(),
          },
          fieldError(nameField),
          { label: "Email address", $: [label()] },
          {
            input: null,
            type: "email",
            placeholder: "jane@example.com",
            $: [inputText()],
            value: (l) => emailField.value(l),
            onInput: (e) =>
              emailField.handleChange((e.target as HTMLInputElement).value),
            onBlur: () => emailField.handleBlur(),
          },
          fieldError(emailField),
        ],
        $: [formGroup({ layout: "vertical" })],
      },
      {
        div: [
          {
            button: "Next: Preferences",
            type: "button",
            $: [button({ color: "primary" })],
            onClick: () => {
              nameField.handleBlur();
              emailField.handleBlur();
              const nameOk = nameField.api.getMeta().errors.length === 0
                && nameField.api.state.value.trim().length >= 2;
              const emailOk = emailField.api.getMeta().errors.length === 0
                && /^[^@]+@[^@]+\.[^@]+$/.test(emailField.api.state.value);
              if (nameOk && emailOk) step.set(2);
            },
          },
        ],
        style: {
          display: "flex",
          justifyContent: "flex-end",
          marginTop: themeSpacing(4),
        },
      },
    ],
    style: { display: "flex", flexDirection: "column", gap: themeSpacing(3) },
  };
}

// ── Step 2: Theme & Language ──────────────────────────────────────────────────

function Step2(): DomphyElement<"div"> {
  return {
    div: [
      {
        h2: "Preferences",
        $: [heading()],
        style: { marginBottom: themeSpacing(3) },
      },
      {
        fieldset: [
          { legend: "Display settings" },
          { label: "Theme", $: [label()] },
          {
            select: THEME_OPTIONS.map((opt) => ({
              option: opt.label,
              value: opt.value,
            })),
            $: [select()],
            value: (l) => themeField.value(l),
            onChange: (e) =>
              themeField.handleChange((e.target as HTMLSelectElement).value),
          },
          { label: "Language", $: [label()] },
          {
            select: LANGUAGE_OPTIONS.map((opt) => ({
              option: opt.label,
              value: opt.value,
            })),
            $: [select()],
            value: (l) => languageField.value(l),
            onChange: (e) =>
              languageField.handleChange((e.target as HTMLSelectElement).value),
          },
        ],
        $: [formGroup({ layout: "vertical" })],
      },
      {
        div: [
          {
            button: "Back",
            type: "button",
            $: [button()],
            onClick: () => step.set(1),
          },
          {
            button: "Next: Review",
            type: "button",
            $: [button({ color: "primary" })],
            onClick: () => step.set(3),
          },
        ],
        style: {
          display: "flex",
          justifyContent: "space-between",
          marginTop: themeSpacing(4),
        },
      },
    ],
    style: { display: "flex", flexDirection: "column", gap: themeSpacing(3) },
  };
}

// ── Step 3: Review & Submit ───────────────────────────────────────────────────

function ReviewRow(fieldLabel: string, value: string): DomphyElement<"div"> {
  return {
    div: [
      { p: fieldLabel, $: [paragraph()], style: { fontWeight: "600" } },
      { p: value || "—", $: [paragraph()] },
    ],
    style: {
      display: "flex",
      justifyContent: "space-between",
      paddingBlock: themeSpacing(2),
      borderBottom: `1px solid`,
    },
  };
}

function Step3(): DomphyElement<"div"> {
  return {
    div: [
      {
        h2: "Review & Submit",
        $: [heading()],
        style: { marginBottom: themeSpacing(3) },
      },
      {
        div: [
          (l) => ReviewRow("Full name", nameField.value(l) as string),
          (l) => ReviewRow("Email address", emailField.value(l) as string),
          (l) => ReviewRow("Theme", themeField.value(l) as string),
          (l) => ReviewRow("Language", languageField.value(l) as string),
        ],
        style: {
          display: "flex",
          flexDirection: "column",
          gap: themeSpacing(1),
          padding: themeSpacing(3),
          borderRadius: themeSpacing(2),
        },
      },
      {
        div: [
          {
            button: "Back",
            type: "button",
            $: [button()],
            onClick: () => step.set(2),
          },
          {
            button: (l) => (form.isSubmitting(l) ? "Submitting…" : "Submit"),
            type: "submit",
            $: [button({ color: "primary" })],
            ariaDisabled: (l) => !form.canSubmit(l),
          },
        ],
        style: {
          display: "flex",
          justifyContent: "space-between",
          marginTop: themeSpacing(4),
        },
      },
    ],
    style: { display: "flex", flexDirection: "column", gap: themeSpacing(3) },
  };
}

// ── Root App ──────────────────────────────────────────────────────────────────

const App: DomphyElement<"div"> = {
  div: [
    {
      h1: "Setup Wizard",
      $: [heading()],
      style: { marginBottom: themeSpacing(2) },
    },
    ProgressIndicator(),
    {
      form: (l) => {
        const current = step.get(l);
        if (current === 1) return [Step1()];
        if (current === 2) return [Step2()];
        return [Step3()];
      },
      onSubmit: (e) => {
        (e as Event).preventDefault();
        form.handleSubmit();
      },
      _onRemove: () => form.destroy(),
      style: {
        display: "flex",
        flexDirection: "column",
        gap: themeSpacing(3),
      },
    },
  ],
  dataTheme: "light",
  style: {
    display: "flex",
    flexDirection: "column",
    gap: themeSpacing(3),
    maxWidth: themeSpacing(120),
    margin: "0 auto",
    padding: themeSpacing(6),
  },
};

new ElementNode(App).render(document.getElementById("app")!);

import { ElementNode, toState } from "@domphy/core"
import { themeApply, themeColor, themeSpacing } from "@domphy/theme"
import {
  button,
  card,
  formGroup,
  heading,
  inputText,
  paragraph,
  progress,
  select,
  small,
} from "@domphy/ui"
import { createForm } from "@domphy/form/domphy"

themeApply()

// --- Step state (0 = name/email, 1 = theme/lang, 2 = review) ---
const step = toState(0)
const TOTAL_STEPS = 3

// --- Form ---
const form = createForm({
  defaultValues: {
    name: "",
    email: "",
    theme: "light",
    language: "en",
  },
  onSubmit: async ({ value }) => {
    alert(`Submitted!\n${JSON.stringify(value, null, 2)}`)
  },
})

const nameField = form.field("name")
const emailField = form.field("email")
const themeField = form.field("theme")
const languageField = form.field("language")

// --- Helpers ---
function goNext(): void {
  const current = step.get()
  if (current < TOTAL_STEPS - 1) step.set(current + 1)
}

function goBack(): void {
  const current = step.get()
  if (current > 0) step.set(current - 1)
}

// --- Progress indicator ---
function ProgressIndicator() {
  return {
    div: [
      {
        progress: null,
        value: (l: import("@domphy/core").Listener) => step.get(l) + 1,
        max: TOTAL_STEPS,
        $: [progress({ color: "neutral", accentColor: "primary" })],
        style: { width: "100%" },
      },
      {
        small: (l: import("@domphy/core").Listener) =>
          `Step ${step.get(l) + 1} of ${TOTAL_STEPS}`,
        $: [small({ color: "neutral" })],
      },
    ],
    style: {
      display: "flex",
      flexDirection: "column",
      gap: themeSpacing(2),
      marginBottom: themeSpacing(4),
    },
  }
}

// --- Step 1: Name & Email ---
function Step1() {
  return {
    div: [
      {
        h2: "Your Information",
        $: [heading({ color: "neutral" })],
      },
      {
        fieldset: [
          {
            label: "Full Name",
            $: [formGroup({ layout: "vertical" })],
          },
          {
            input: null,
            type: "text",
            placeholder: "Enter your name",
            value: (l: import("@domphy/core").Listener) => nameField.state.value(l),
            onInput: (e: Event) =>
              nameField.handleChange((e.target as HTMLInputElement).value),
            $: [inputText({ color: "neutral", accentColor: "primary" })],
          },
        ],
        $: [formGroup({ layout: "vertical" })],
        style: { border: "none", padding: "0" },
      },
      {
        fieldset: [
          {
            label: "Email Address",
            $: [formGroup({ layout: "vertical" })],
          },
          {
            input: null,
            type: "email",
            placeholder: "Enter your email",
            value: (l: import("@domphy/core").Listener) => emailField.state.value(l),
            onInput: (e: Event) =>
              emailField.handleChange((e.target as HTMLInputElement).value),
            $: [inputText({ color: "neutral", accentColor: "primary" })],
          },
        ],
        $: [formGroup({ layout: "vertical" })],
        style: { border: "none", padding: "0" },
      },
    ],
    style: {
      display: "flex",
      flexDirection: "column",
      gap: themeSpacing(4),
    },
  }
}

// --- Step 2: Theme & Language ---
function Step2() {
  return {
    div: [
      {
        h2: "Preferences",
        $: [heading({ color: "neutral" })],
      },
      {
        fieldset: [
          {
            label: "Theme",
            $: [formGroup({ layout: "vertical" })],
          },
          {
            select: [
              { option: "Light", value: "light" },
              { option: "Dark", value: "dark" },
              { option: "System", value: "system" },
            ],
            value: (l: import("@domphy/core").Listener) => themeField.state.value(l),
            onChange: (e: Event) =>
              themeField.handleChange((e.target as HTMLSelectElement).value),
            $: [select({ color: "neutral", accentColor: "primary" })],
          },
        ],
        $: [formGroup({ layout: "vertical" })],
        style: { border: "none", padding: "0" },
      },
      {
        fieldset: [
          {
            label: "Language",
            $: [formGroup({ layout: "vertical" })],
          },
          {
            select: [
              { option: "English", value: "en" },
              { option: "Vietnamese", value: "vi" },
              { option: "French", value: "fr" },
              { option: "Japanese", value: "ja" },
            ],
            value: (l: import("@domphy/core").Listener) => languageField.state.value(l),
            onChange: (e: Event) =>
              languageField.handleChange((e.target as HTMLSelectElement).value),
            $: [select({ color: "neutral", accentColor: "primary" })],
          },
        ],
        $: [formGroup({ layout: "vertical" })],
        style: { border: "none", padding: "0" },
      },
    ],
    style: {
      display: "flex",
      flexDirection: "column",
      gap: themeSpacing(4),
    },
  }
}

// --- Step 3: Review & Submit ---
function Step3() {
  return {
    div: [
      {
        h2: "Review Your Details",
        $: [heading({ color: "neutral" })],
      },
      {
        dl: [
          { dt: "Name" },
          {
            dd: (l: import("@domphy/core").Listener) => nameField.state.value(l) || "—",
          },
          { dt: "Email" },
          {
            dd: (l: import("@domphy/core").Listener) => emailField.state.value(l) || "—",
          },
          { dt: "Theme" },
          {
            dd: (l: import("@domphy/core").Listener) => themeField.state.value(l),
          },
          { dt: "Language" },
          {
            dd: (l: import("@domphy/core").Listener) => languageField.state.value(l),
          },
        ],
        style: {
          display: "grid",
          gridTemplateColumns: "auto 1fr",
          gap: themeSpacing(2),
        },
      },
      {
        p: "Please review the information above before submitting.",
        $: [paragraph({ color: "neutral" })],
      },
    ],
    style: {
      display: "flex",
      flexDirection: "column",
      gap: themeSpacing(4),
    },
  }
}

// --- Step content (reactive) ---
function StepContent() {
  return {
    div: (l: import("@domphy/core").Listener) => {
      const current = step.get(l)
      if (current === 0) return [Step1()]
      if (current === 1) return [Step2()]
      return [Step3()]
    },
  }
}

// --- Navigation buttons ---
function NavButtons() {
  return {
    div: [
      {
        button: "Back",
        type: "button",
        onClick: () => goBack(),
        $: [button({ color: "neutral" })],
        style: {
          visibility: (l: import("@domphy/core").Listener) =>
            step.get(l) === 0 ? "hidden" : "visible",
        },
      },
      {
        button: (l: import("@domphy/core").Listener) =>
          step.get(l) === TOTAL_STEPS - 1 ? "Submit" : "Next",
        type: "button",
        onClick: () => {
          if (step.get() === TOTAL_STEPS - 1) {
            form.handleSubmit()
          } else {
            goNext()
          }
        },
        $: [button({ color: "primary" })],
      },
    ],
    style: {
      display: "flex",
      justifyContent: "space-between",
      marginTop: themeSpacing(6),
    },
  }
}

// --- Root app ---
const App = {
  div: [
    {
      div: [
        ProgressIndicator(),
        StepContent(),
        NavButtons(),
      ],
      $: [card({ color: "neutral" })],
      style: {
        width: "100%",
        maxWidth: "480px",
        margin: "0 auto",
      },
    },
  ],
  dataTheme: "light",
  style: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    minHeight: "100vh",
    padding: themeSpacing(6),
    backgroundColor: (l: import("@domphy/core").Listener) =>
      themeColor(l, "shift-1", "neutral"),
  },
}

new ElementNode(App).render(document.getElementById("app")!)

import { useState } from "react";

interface PersonalInfo {
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
}

interface Preferences {
  theme: string;
  notifications: boolean;
  language: string;
  newsletter: boolean;
}

interface FormData {
  personalInfo: PersonalInfo;
  preferences: Preferences;
}

const initialFormData: FormData = {
  personalInfo: {
    firstName: "",
    lastName: "",
    email: "",
    phone: "",
  },
  preferences: {
    theme: "light",
    notifications: true,
    language: "en",
    newsletter: false,
  },
};

const steps = ["Personal Info", "Preferences", "Review & Submit"];

export default function WizardForm() {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<FormData>(initialFormData);
  const [submitted, setSubmitted] = useState(false);

  const updatePersonalInfo = (field: keyof PersonalInfo, value: string) => {
    setFormData((prev) => ({
      ...prev,
      personalInfo: { ...prev.personalInfo, [field]: value },
    }));
  };

  const updatePreferences = (field: keyof Preferences, value: string | boolean) => {
    setFormData((prev) => ({
      ...prev,
      preferences: { ...prev.preferences, [field]: value },
    }));
  };

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep((prev) => prev + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep((prev) => prev - 1);
    }
  };

  const handleSubmit = () => {
    setSubmitted(true);
  };

  if (submitted) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.successIcon}>✓</div>
          <h2 style={styles.successTitle}>Form Submitted!</h2>
          <p style={styles.successText}>Thank you, {formData.personalInfo.firstName}. Your information has been saved.</p>
          <button
            style={styles.primaryButton}
            onClick={() => {
              setSubmitted(false);
              setCurrentStep(0);
              setFormData(initialFormData);
            }}
          >
            Start Over
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>Registration Wizard</h1>

        {/* Progress Indicator */}
        <div style={styles.progressContainer}>
          {steps.map((step, index) => (
            <div key={step} style={styles.stepWrapper}>
              <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
                <div
                  style={{
                    ...styles.stepCircle,
                    backgroundColor:
                      index < currentStep ? "#22c55e" : index === currentStep ? "#3b82f6" : "#e5e7eb",
                    color: index <= currentStep ? "#fff" : "#9ca3af",
                  }}
                >
                  {index < currentStep ? "✓" : index + 1}
                </div>
                <span
                  style={{
                    ...styles.stepLabel,
                    color: index === currentStep ? "#3b82f6" : index < currentStep ? "#22c55e" : "#9ca3af",
                    fontWeight: index === currentStep ? 600 : 400,
                  }}
                >
                  {step}
                </span>
              </div>
              {index < steps.length - 1 && (
                <div
                  style={{
                    ...styles.connector,
                    backgroundColor: index < currentStep ? "#22c55e" : "#e5e7eb",
                  }}
                />
              )}
            </div>
          ))}
        </div>

        {/* Step Content */}
        <div style={styles.stepContent}>
          {currentStep === 0 && (
            <div>
              <h2 style={styles.stepTitle}>Personal Information</h2>
              <div style={styles.fieldGroup}>
                <div style={styles.row}>
                  <div style={styles.field}>
                    <label style={styles.label}>First Name</label>
                    <input
                      style={styles.input}
                      type="text"
                      placeholder="John"
                      value={formData.personalInfo.firstName}
                      onChange={(e) => updatePersonalInfo("firstName", e.target.value)}
                    />
                  </div>
                  <div style={styles.field}>
                    <label style={styles.label}>Last Name</label>
                    <input
                      style={styles.input}
                      type="text"
                      placeholder="Doe"
                      value={formData.personalInfo.lastName}
                      onChange={(e) => updatePersonalInfo("lastName", e.target.value)}
                    />
                  </div>
                </div>
                <div style={styles.field}>
                  <label style={styles.label}>Email Address</label>
                  <input
                    style={styles.input}
                    type="email"
                    placeholder="john.doe@example.com"
                    value={formData.personalInfo.email}
                    onChange={(e) => updatePersonalInfo("email", e.target.value)}
                  />
                </div>
                <div style={styles.field}>
                  <label style={styles.label}>Phone Number</label>
                  <input
                    style={styles.input}
                    type="tel"
                    placeholder="+1 (555) 000-0000"
                    value={formData.personalInfo.phone}
                    onChange={(e) => updatePersonalInfo("phone", e.target.value)}
                  />
                </div>
              </div>
            </div>
          )}

          {currentStep === 1 && (
            <div>
              <h2 style={styles.stepTitle}>Preferences</h2>
              <div style={styles.fieldGroup}>
                <div style={styles.field}>
                  <label style={styles.label}>Theme</label>
                  <select
                    style={styles.input}
                    value={formData.preferences.theme}
                    onChange={(e) => updatePreferences("theme", e.target.value)}
                  >
                    <option value="light">Light</option>
                    <option value="dark">Dark</option>
                    <option value="system">System Default</option>
                  </select>
                </div>
                <div style={styles.field}>
                  <label style={styles.label}>Language</label>
                  <select
                    style={styles.input}
                    value={formData.preferences.language}
                    onChange={(e) => updatePreferences("language", e.target.value)}
                  >
                    <option value="en">English</option>
                    <option value="fr">French</option>
                    <option value="de">German</option>
                    <option value="es">Spanish</option>
                  </select>
                </div>
                <div style={styles.checkboxField}>
                  <input
                    type="checkbox"
                    id="notifications"
                    style={styles.checkbox}
                    checked={formData.preferences.notifications}
                    onChange={(e) => updatePreferences("notifications", e.target.checked)}
                  />
                  <label htmlFor="notifications" style={styles.checkboxLabel}>
                    Enable push notifications
                  </label>
                </div>
                <div style={styles.checkboxField}>
                  <input
                    type="checkbox"
                    id="newsletter"
                    style={styles.checkbox}
                    checked={formData.preferences.newsletter}
                    onChange={(e) => updatePreferences("newsletter", e.target.checked)}
                  />
                  <label htmlFor="newsletter" style={styles.checkboxLabel}>
                    Subscribe to newsletter
                  </label>
                </div>
              </div>
            </div>
          )}

          {currentStep === 2 && (
            <div>
              <h2 style={styles.stepTitle}>Review & Submit</h2>
              <div style={styles.reviewSection}>
                <h3 style={styles.reviewSectionTitle}>Personal Information</h3>
                <div style={styles.reviewGrid}>
                  <ReviewRow label="First Name" value={formData.personalInfo.firstName || "—"} />
                  <ReviewRow label="Last Name" value={formData.personalInfo.lastName || "—"} />
                  <ReviewRow label="Email" value={formData.personalInfo.email || "—"} />
                  <ReviewRow label="Phone" value={formData.personalInfo.phone || "—"} />
                </div>
              </div>
              <div style={styles.reviewSection}>
                <h3 style={styles.reviewSectionTitle}>Preferences</h3>
                <div style={styles.reviewGrid}>
                  <ReviewRow label="Theme" value={formData.preferences.theme} />
                  <ReviewRow label="Language" value={formData.preferences.language.toUpperCase()} />
                  <ReviewRow label="Notifications" value={formData.preferences.notifications ? "Enabled" : "Disabled"} />
                  <ReviewRow label="Newsletter" value={formData.preferences.newsletter ? "Subscribed" : "Not subscribed"} />
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Navigation Buttons */}
        <div style={styles.navigation}>
          <button
            style={{ ...styles.secondaryButton, visibility: currentStep === 0 ? "hidden" : "visible" }}
            onClick={handleBack}
          >
            ← Back
          </button>
          <span style={styles.stepCounter}>
            Step {currentStep + 1} of {steps.length}
          </span>
          {currentStep < steps.length - 1 ? (
            <button style={styles.primaryButton} onClick={handleNext}>
              Next →
            </button>
          ) : (
            <button style={styles.submitButton} onClick={handleSubmit}>
              Submit ✓
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

function ReviewRow({ label, value }: { label: string; value: string }) {
  return (
    <div style={styles.reviewRow}>
      <span style={styles.reviewLabel}>{label}</span>
      <span style={styles.reviewValue}>{value}</span>
    </div>
  );
}

