                                            type: "checkbox",
                                            checked: row.getIsSelected(),
                                            disabled: !row.getCanSelect(),
                                            onChange: () => row.toggleSelected(),
                                            $: [inputCheckbox()],
                                        },
                                        _key: cell.id,
                                    }
                                }
                                return {
                                    td: cell.column.id === "salary"
