                            }),
                            _key: row.id,
                        })),
                    },
                ]
            },
            $: [tableUI()],
        },
        {
            div: (l) => {
                version(l)
                const selected = table.getSelectedRowModel().rows
                if (selected.length === 0) return []
                return [
                    {
                        span: `${selected.length} row${selected.length > 1 ? "s" : ""} selected`,
                    },
                ]
            },
            style: {
                fontSize: "0.875rem",
                minHeight: themeSpacing(6),
            },
        },
    ],
    dataTheme: "light",
    style: {
        display: "flex",
        flexDirection: "column",
        gap: themeSpacing(3),
        padding: themeSpacing(4),
    },
