import {
  type DomphyElement,
  render,
  toState,
} from "@domphy/core";
import { themeColor, themeSpacing } from "@domphy/theme";
import {
  button,
  card,
  heading,
  inputCheckbox,
  inputSearch,
  small,
  table,
} from "@domphy/ui";
import {
  createColumnHelper,
  getCoreRowModel,
  getFilteredRowModel,
  getSortedRowModel,
} from "@domphy/table";
import { createDomphyTable } from "@domphy/table/domphy";

// --- Data ---

interface Employee {
  id: number;
  name: string;
  department: string;
  salary: number;
}

const employees: Employee[] = [
  { id: 1, name: "Alice Martin", department: "Engineering", salary: 95000 },
  { id: 2, name: "Bob Chen", department: "Design", salary: 82000 },
  { id: 3, name: "Carol Smith", department: "Marketing", salary: 74000 },
  { id: 4, name: "David Lee", department: "Engineering", salary: 105000 },
  { id: 5, name: "Eve Torres", department: "HR", salary: 68000 },
  { id: 6, name: "Frank Nguyen", department: "Engineering", salary: 98000 },
  { id: 7, name: "Grace Kim", department: "Design", salary: 87000 },
  { id: 8, name: "Hiro Tanaka", department: "Finance", salary: 91000 },
  { id: 9, name: "Iris Patel", department: "Marketing", salary: 76000 },
  { id: 10, name: "Jake Wilson", department: "Finance", salary: 88000 },
];

// --- Column definitions ---

const helper = createColumnHelper<Employee>();

const columns = [
  // Selection display column — no accessor, renders a checkbox
  helper.display({
    id: "select",
    header: ({ table: t }) => {
      const allSelected = t.getIsAllRowsSelected();
      const someSelected = t.getIsSomeRowsSelected();
      return { allSelected, someSelected, toggleAll: () => t.toggleAllRowsSelected() };
    },
    cell: ({ row }) => ({
      checked: row.getIsSelected(),
      toggle: () => row.toggleSelected(),
    }),
    enableSorting: false,
  }),
  helper.accessor("id", {
    header: "ID",
    enableSorting: true,
  }),
  helper.accessor("name", {
    header: "Name",
    enableSorting: true,
    filterFn: "includesString",
  }),
  helper.accessor("department", {
    header: "Department",
    enableSorting: true,
    filterFn: "includesString",
  }),
  helper.accessor("salary", {
    header: "Salary",
    enableSorting: true,
    cell: (info) => `$${info.getValue().toLocaleString()}`,
  }),
];

// --- Reactive state ---

const filterText = toState("", "filterText");

// --- Table instance ---

const dt = createDomphyTable<Employee>({
  data: employees,
  columns,
  getCoreRowModel: getCoreRowModel(),
  getSortedRowModel: getSortedRowModel(),
  getFilteredRowModel: getFilteredRowModel(),
  enableRowSelection: true,
  enableMultiRowSelection: true,
  globalFilterFn: "includesString",
  initialState: {
    sorting: [],
    rowSelection: {},
    globalFilter: "",
  },
});

// Keep global filter in sync with our reactive state
filterText._subscribe(() => {
  dt.table.setGlobalFilter(filterText.get());
});

// --- Sort indicator helper ---

function sortIndicator(columnId: string): (l: unknown) => string {
  return (l) => {
    dt.version(l as any);
    const sorted = dt.table.getColumn(columnId)?.getIsSorted();
    if (sorted === "asc") return " ▲";
    if (sorted === "desc") return " ▼";
    return "";
  };
}

// --- Header cell builder ---

function headerCell(col: ReturnType<typeof helper.accessor> | any): DomphyElement<"th"> {
  const colId = col.id ?? col.accessorKey ?? "";
  const label =
    typeof col.header === "string" ? col.header : colId;
  const canSort = col.enableSorting !== false;

  if (!canSort) {
    return {
      th: label,
    };
  }

  return {
    th: {
      button: [label, { span: (l: any) => sortIndicator(colId)(l) }],
      $: [button({ color: "neutral" })],
      onClick: () => {
        dt.table.getColumn(colId)?.toggleSorting();
      },
      style: {
        cursor: "pointer",
        background: "none",
        border: "none",
        width: "100%",
        textAlign: "left",
      },
    },
  };
}

// --- Row builder ---

function buildRows(): (l: any) => DomphyElement<"tr">[] {
  return (l) => {
    dt.version(l);
    return dt.table.getRowModel().rows.map((row) => ({
      tr: [
        // Selection checkbox cell
        {
          td: {
            input: null,
            type: "checkbox",
            checked: row.getIsSelected(),
            onChange: () => row.toggleSelected(),
            $: [inputCheckbox()],
          },
        },
        // Data cells
        ...row.getVisibleCells().slice(1).map((cell) => ({
          td: String(cell.renderValue() ?? ""),
        })),
      ],
      style: row.getIsSelected()
        ? { backgroundColor: (lc: any) => themeColor(lc, "shift-2", "primary") }
        : {},
      _key: row.id,
    }));
  };
}

// --- Selection count footer ---

function selectionCount(): (l: any) => DomphyElement<"small"> {
  return (l) => {
    dt.version(l);
    const count = Object.keys(dt.table.getState().rowSelection).filter(
      (k) => dt.table.getState().rowSelection[k],
    ).length;
    return {
      small: count === 0 ? "No rows selected" : `${count} row${count > 1 ? "s" : ""} selected`,
      $: [small()],
    };
  };
}

// --- App root ---

const App: DomphyElement<"div"> = {
  div: [
    // Title
    {
      h2: "Employee Data Grid",
      $: [heading()],
    },
    // Filter input
    {
      div: {
        input: null,
        placeholder: "Search all columns…",
        value: (l) => filterText.get(l),
        onInput: (e: Event) => filterText.set((e.target as HTMLInputElement).value),
        $: [inputSearch()],
      },
      style: {
        marginBottom: themeSpacing(4),
        display: "flex",
      },
    },
    // Table card
    {
      div: {
        div: {
          table: (l: any): DomphyElement<"table"> => {
            dt.version(l);
            const headerGroups = dt.table.getHeaderGroups();
            return {
              table: [
                // thead
                {
                  thead: headerGroups.map((group) => ({
                    tr: group.headers.map((header) => {
                      const colId = header.column.id;
                      const canSort = header.column.getCanSort();
                      const label =
                        typeof header.column.columnDef.header === "string"
                          ? header.column.columnDef.header
                          : colId === "select"
                          ? ""
                          : colId;

                      if (colId === "select") {
                        const allSelected = dt.table.getIsAllRowsSelected();
                        const someSelected = dt.table.getIsSomeRowsSelected();
                        return {
                          th: {
                            input: null,
                            type: "checkbox",
                            checked: allSelected,
                            indeterminate: !allSelected && someSelected,
                            onChange: () => dt.table.toggleAllRowsSelected(),
                            $: [inputCheckbox()],
                          },
                        };
                      }

                      if (!canSort) {
                        return { th: label };
                      }

                      const sorted = header.column.getIsSorted();
                      const indicator = sorted === "asc" ? " ▲" : sorted === "desc" ? " ▼" : "";

                      return {
                        th: {
                          button: `${label}${indicator}`,
                          onClick: header.column.getToggleSortingHandler(),
                          $: [button({ color: "neutral" })],
                          style: {
                            width: "100%",
                            justifyContent: "flex-start",
                          },
                        },
                      };
                    }),
                    _key: group.id,
                  })),
                },
                // tbody
                {
                  tbody: dt.table.getRowModel().rows.map((row) => ({
                    tr: [
                      {
                        td: {
                          input: null,
                          type: "checkbox",
                          checked: row.getIsSelected(),
                          onChange: () => row.toggleSelected(),
                          $: [inputCheckbox()],
                        },
                      },
                      ...row.getVisibleCells().slice(1).map((cell) => ({
                        td: String(cell.renderValue() ?? ""),
                      })),
                    ],
                    style: row.getIsSelected()
                      ? {
                          backgroundColor: (lc: any) =>
                            themeColor(lc, "shift-2", "primary"),
                        }
                      : {},
                    _key: row.id,
                  })),
                },
              ],
              $: [table()],
            };
          },
        },
        $: [card()],
        style: {
          overflow: "auto",
        },
      },
    },
    // Footer
    {
      div: (l: any) => {
        dt.version(l);
        const selected = dt.table.getSelectedRowModel().rows.length;
        return {
          div: {
            small: selected === 0
              ? "No rows selected"
              : `${selected} row${selected !== 1 ? "s" : ""} selected`,
            $: [small()],
          },
        };
      },
      style: {
        marginTop: themeSpacing(2),
        display: "flex",
        alignItems: "center",
        gap: themeSpacing(2),
      },
    },
  ],
  style: {
    padding: themeSpacing(6),
    maxWidth: themeSpacing(256),
    margin: "0 auto",
    display: "flex",
    flexDirection: "column",
    gap: themeSpacing(4),
  },
};

