import { useState, useMemo } from "react";

interface Employee {
  id: number;
  name: string;
  department: string;
  salary: number;
}

const INITIAL_DATA: Employee[] = [
  { id: 1, name: "Alice Johnson", department: "Engineering", salary: 95000 },
  { id: 2, name: "Bob Smith", department: "Marketing", salary: 72000 },
  { id: 3, name: "Carol White", department: "Engineering", salary: 105000 },
  { id: 4, name: "David Brown", department: "HR", salary: 68000 },
  { id: 5, name: "Eva Martinez", department: "Finance", salary: 88000 },
  { id: 6, name: "Frank Lee", department: "Engineering", salary: 112000 },
  { id: 7, name: "Grace Kim", department: "Marketing", salary: 75000 },
  { id: 8, name: "Henry Davis", department: "Finance", salary: 91000 },
  { id: 9, name: "Iris Chen", department: "HR", salary: 65000 },
  { id: 10, name: "Jack Wilson", department: "Engineering", salary: 98000 },
];

type SortKey = keyof Employee;
type SortDir = "asc" | "desc";

export default function DataGrid() {
  const [filter, setFilter] = useState("");
  const [sortKey, setSortKey] = useState<SortKey>("id");
  const [sortDir, setSortDir] = useState<SortDir>("asc");
  const [selected, setSelected] = useState<Set<number>>(new Set());

  const filtered = useMemo(() => {
    const lower = filter.toLowerCase();
    return INITIAL_DATA.filter(
      (row) =>
        row.name.toLowerCase().includes(lower) ||
        row.department.toLowerCase().includes(lower) ||
        String(row.id).includes(lower) ||
        String(row.salary).includes(lower)
    );
  }, [filter]);

  const sorted = useMemo(() => {
    return [...filtered].sort((a, b) => {
      const av = a[sortKey];
      const bv = b[sortKey];
      if (av < bv) return sortDir === "asc" ? -1 : 1;
      if (av > bv) return sortDir === "asc" ? 1 : -1;
      return 0;
    });
  }, [filtered, sortKey, sortDir]);

  function handleSort(key: SortKey) {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("asc");
    }
  }

  function toggleRow(id: number) {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  function toggleAll() {
    if (selected.size === sorted.length) {
      setSelected(new Set());
    } else {
      setSelected(new Set(sorted.map((r) => r.id)));
    }
  }

  const allSelected = sorted.length > 0 && selected.size === sorted.length;
  const someSelected = selected.size > 0 && selected.size < sorted.length;

  function sortIndicator(key: SortKey) {
    if (sortKey !== key) return " ⇅";
    return sortDir === "asc" ? " ↑" : " ↓";
  }

  return (
    <div style={{ fontFamily: "system-ui, sans-serif", padding: 24, maxWidth: 800 }}>
      <h2 style={{ marginBottom: 16 }}>Employee Data Grid</h2>

      <input
        type="text"
        placeholder="Filter by any field..."
        value={filter}
        onChange={(e) => setFilter(e.target.value)}
        style={{
          marginBottom: 16,
          padding: "8px 12px",
          width: "100%",
          boxSizing: "border-box",
          border: "1px solid #ccc",
          borderRadius: 4,
          fontSize: 14,
        }}
      />

      {selected.size > 0 && (
        <div style={{ marginBottom: 8, fontSize: 13, color: "#555" }}>
          {selected.size} row{selected.size > 1 ? "s" : ""} selected
        </div>
      )}

      <table
        style={{
          width: "100%",
          borderCollapse: "collapse",
          fontSize: 14,
        }}
      >
        <thead>
          <tr style={{ backgroundColor: "#f0f0f0" }}>
            <th style={thStyle}>
              <input
                type="checkbox"
                checked={allSelected}
                ref={(el) => {
                  if (el) el.indeterminate = someSelected;
                }}
                onChange={toggleAll}
              />
            </th>
            {(["id", "name", "department", "salary"] as SortKey[]).map((key) => (
              <th
                key={key}
                style={{ ...thStyle, cursor: "pointer", userSelect: "none" }}
                onClick={() => handleSort(key)}
              >
                {key.charAt(0).toUpperCase() + key.slice(1)}
                {sortIndicator(key)}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sorted.length === 0 ? (
            <tr>
              <td colSpan={5} style={{ textAlign: "center", padding: 24, color: "#888" }}>
                No results found.
              </td>
            </tr>
          ) : (
            sorted.map((row) => (
              <tr
                key={row.id}
                style={{
                  backgroundColor: selected.has(row.id) ? "#e8f0fe" : "white",
                  borderBottom: "1px solid #e0e0e0",
                  cursor: "pointer",
                }}
                onClick={() => toggleRow(row.id)}
              >
                <td style={tdStyle}>
                  <input
                    type="checkbox"
                    checked={selected.has(row.id)}
                    onChange={() => toggleRow(row.id)}
                    onClick={(e) => e.stopPropagation()}
                  />
                </td>
                <td style={tdStyle}>{row.id}</td>
                <td style={tdStyle}>{row.name}</td>
                <td style={tdStyle}>{row.department}</td>
                <td style={{ ...tdStyle, textAlign: "right" }}>
                  ${row.salary.toLocaleString()}
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

const thStyle: React.CSSProperties = {
  padding: "10px 12px",
  textAlign: "left",
  borderBottom: "2px solid #ccc",
  fontWeight: 600,
};

const tdStyle: React.CSSProperties = {
  padding: "10px 12px",
};

import { type DomphyElement, ElementNode } from "@domphy/core";
import { themeApply, themeColor, themeSpacing } from "@domphy/theme";
import { spinner } from "@domphy/ui";
import { QueryClient } from "@domphy/query";
import { createInfiniteQuery } from "@domphy/query/domphy";
import { createVirtualizer } from "@domphy/virtual/domphy";

// --- Mock data ---

interface Post {
  id: number;
  title: string;
  body: string;
}

async function fetchPosts({ pageParam }: { pageParam: number }): Promise<{
  posts: Post[];
  nextPage: number | null;
}> {
  await new Promise((resolve) => setTimeout(resolve, 400));
  const page = pageParam as number;
  const posts: Post[] = Array.from({ length: 10 }, (_, i) => {
    const id = page * 10 + i + 1;
    return {
      id,
      title: `Post #${id}`,
      body: `This is the body of post number ${id}. Loaded from page ${page + 1}.`,
    };
  });
  const nextPage = page < 9 ? page + 1 : null;
  return { posts, nextPage };
}

// --- Query client ---

const client = new QueryClient();

const query = createInfiniteQuery<
  { posts: Post[]; nextPage: number | null },
  Error,
  { posts: Post[]; nextPage: number | null },
  readonly ["posts"],
  number
>(client, {
  queryKey: ["posts"] as const,
  queryFn: fetchPosts,
  initialPageParam: 0,
  getNextPageParam: (lastPage) => lastPage.nextPage ?? undefined,
});

// --- Flatten pages into a single post array ---

function allPosts(): Post[] {
  const data = query.data();
  if (!data) return [];
  return data.pages.flatMap((page) => page.posts);
}

// --- Virtualizer ---

const ITEM_HEIGHT = 80;
const OVERSCAN = 5;

const list = createVirtualizer<HTMLDivElement, HTMLDivElement>({
  count: 0,
  estimateSize: () => ITEM_HEIGHT,
  overscan: OVERSCAN,
});

// Keep virtualizer count in sync with fetched posts
query.state.addListener("data", () => {
  list.setOptions({ count: allPosts().length });
});

// --- Infinite scroll sentinel: load next page when near the bottom ---

function handleScroll(scrollEl: HTMLDivElement): void {
  const { scrollTop, scrollHeight, clientHeight } = scrollEl;
  if (
    scrollHeight - scrollTop - clientHeight < ITEM_HEIGHT * 2 &&
    query.hasNextPage() &&
    !query.isFetchingNextPage()
  ) {
    query.fetchNextPage();
  }
}

// --- UI blocks ---

function PostItem(post: Post, item: { size: number; start: number; key: string | number }): DomphyElement<"div"> {
  return {
    div: [
      {
        div: post.title,
        style: {
          fontWeight: "600",
          color: (l) => themeColor(l, "shift-9"),
          fontSize: "0.95rem",
          marginBottom: themeSpacing(1),
        },
      },
      {
        div: post.body,
        style: {
          color: (l) => themeColor(l, "shift-8"),
          fontSize: "0.85rem",
          overflow: "hidden",
          whiteSpace: "nowrap",
          textOverflow: "ellipsis",
        },
      },
    ],
    style: {
      position: "absolute",
      top: "0",
      left: "0",
      width: "100%",
      height: `${item.size}px`,
      transform: `translateY(${item.start}px)`,
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      paddingInline: themeSpacing(4),
      boxSizing: "border-box",
      borderBottom: (l) => `1px solid ${themeColor(l, "shift-3")}`,
    },
    _key: item.key,
  };
}

function LoadingMore(): DomphyElement<"div"> {
  return {
    div: [
      {
        span: null,
        $: [spinner()],
      },
      {
        span: "Loading more…",
        style: {
          fontSize: "0.85rem",
          color: (l) => themeColor(l, "shift-8"),
        },
      },
    ],
    style: {
      display: "flex",
      alignItems: "center",
      gap: themeSpacing(2),
      justifyContent: "center",
      padding: `${themeSpacing(3)} 0`,
    },
  };
}

function EndMessage(): DomphyElement<"div"> {
  return {
    div: "All posts loaded.",
    style: {
      textAlign: "center",
      padding: `${themeSpacing(3)} 0`,
      fontSize: "0.85rem",
      color: (l) => themeColor(l, "shift-7"),
    },
  };
}

// --- Root app ---

themeApply();

const App: DomphyElement<"div"> = {
  div: [
    // Title
    {
      div: "Infinite Scroll Feed",
      style: {
        fontSize: "1.25rem",
        fontWeight: "700",
        color: (l) => themeColor(l, "shift-9"),
        padding: `${themeSpacing(3)} ${themeSpacing(4)}`,
        borderBottom: (l) => `1px solid ${themeColor(l, "shift-3")}`,
      },
    },

    // Initial loading spinner
    {
      div: [
        {
          span: null,
          $: [spinner()],
        },
        {
          span: "Loading posts…",
          style: {
            fontSize: "0.9rem",
            color: (l) => themeColor(l, "shift-8"),
          },
        },
      ],
      hidden: (l) => !query.isPending(l),
      style: {
        display: "flex",
        alignItems: "center",
        gap: themeSpacing(2),
        justifyContent: "center",
        padding: themeSpacing(6),
      },
    },

    // Virtual scroll container
    {
      div: [
        // Total-size spacer; only visible items are absolutely positioned inside
        {
          div: (l) => {
            const posts = allPosts();
            return list.getVirtualItems(l).map((item) => {
              const post = posts[item.index];
              if (!post) return { div: "", _key: item.key };
              return PostItem(post, item);
            });
          },
          style: {
            position: "relative",
            width: "100%",
            height: (l) => `${list.getTotalSize(l)}px`,
          },
        },

        // Fetch-next-page spinner shown below virtual list
        {
          div: (l) => {
            if (query.isFetchingNextPage(l)) return [LoadingMore()];
            if (!query.hasNextPage(l) && !query.isPending(l)) return [EndMessage()];
            return [];
          },
        },
      ],
      hidden: (l) => query.isPending(l),
      style: {
        flex: "1",
        overflow: "auto",
        position: "relative",
      },
      _onMount: (node) => {
        const scrollEl = node.domElement as HTMLDivElement;
        list.setScrollElement(scrollEl);
        node.addEvent("scroll", () => handleScroll(scrollEl));
      },
    },
  ],

  dataTheme: "light",
  style: {
    display: "flex",
    flexDirection: "column",
    height: "480px",
    maxWidth: "600px",
    margin: "0 auto",
    outline: (l) => `1px solid ${themeColor(l, "shift-4")}`,
    borderRadius: themeSpacing(2),
    overflow: "hidden",
    backgroundColor: (l) => themeColor(l, "inherit", "neutral"),
  },

  _onRemove: () => {
    list.destroy();
    query.destroy();
  },
};

new ElementNode(App).render(document.getElementById("app")!);

import type { DomphyElement } from "@domphy/core";
import { ElementNode, toState } from "@domphy/core";
import { themeApply, themeColor, themeSpacing } from "@domphy/theme";
import { button, paragraph, spinner } from "@domphy/ui";
import { QueryClient } from "@domphy/query";
import { createInfiniteQuery } from "@domphy/query/domphy";
import { createVirtualizer } from "@domphy/virtual/domphy";

// ── Mock data + fetch ────────────────────────────────────────────────────────

interface Post {
  id: number;
  title: string;
  body: string;
}

interface Page {
  items: Post[];
  nextCursor: number | null;
}

function mockFetchPage(cursor: number): Promise<Page> {
  return new Promise((resolve) => {
    setTimeout(() => {
      const items: Post[] = Array.from({ length: 10 }, (_, i) => {
        const id = cursor * 10 + i + 1;
        return {
          id,
          title: `Post #${id}`,
          body: `This is the body of post number ${id}.`,
        };
      });
      const nextCursor = cursor < 9 ? cursor + 1 : null; // 10 pages total
      resolve({ items, nextCursor });
    }, 600);
  });
}

// ── Query setup ──────────────────────────────────────────────────────────────

const queryClient = new QueryClient();
queryClient.mount();

const feed = createInfiniteQuery<Page>(queryClient, {
  queryKey: ["posts-feed"],
  queryFn: ({ pageParam }) => mockFetchPage(pageParam as number),
  initialPageParam: 0,
  getNextPageParam: (lastPage) => lastPage.nextCursor,
});

// ── Derived flat list state ──────────────────────────────────────────────────

const allPosts = toState<Post[]>([]);

feed.state.addListener("data", () => {
  const pages = feed.data()?.pages ?? [];
  allPosts.set(pages.flatMap((page) => page.items));
});

// ── Virtualizer ─────────────────────────────────────────────────────────────

const ROW_HEIGHT = 72;

const virtualizer = createVirtualizer<HTMLDivElement, HTMLDivElement>({
  count: 0,
  estimateSize: () => ROW_HEIGHT,
  overscan: 5,
});

// Keep virtualizer count in sync with allPosts length
allPosts.addListener(() => {
  virtualizer.setOptions({ count: allPosts.get().length, estimateSize: () => ROW_HEIGHT });
});

// ── Blocks ───────────────────────────────────────────────────────────────────

function PostRow(post: Post): DomphyElement<"div"> {
  return {
    div: [
      { p: post.title, $: [paragraph()], style: { margin: "0", fontWeight: "600" } },
      { p: post.body, $: [paragraph()], style: { margin: "0" } },
    ],
    style: {
      position: "absolute",
      top: "0",
      left: "0",
      width: "100%",
      boxSizing: "border-box",
      paddingInline: themeSpacing(4),
      paddingBlock: themeSpacing(2),
      display: "flex",
      flexDirection: "column",
      gap: themeSpacing(1),
      borderBottom: (l) => `1px solid ${themeColor(l, "shift-3")}`,
    },
    _key: post.id,
  };
}

// ── Scroll container with sentinel observation ────────────────────────────────

const App: DomphyElement<"div"> = {
  div: [
    // Header
    {
      div: [
        {
          h2: "Infinite Feed",
          style: {
            margin: "0",
            color: (l) => themeColor(l, "shift-9"),
          },
        },
      ],
      style: {
        padding: themeSpacing(4),
        borderBottom: (l) => `1px solid ${themeColor(l, "shift-3")}`,
      },
    },

    // Scroll viewport
    {
      div: [
        // Total-size spacer with absolutely-positioned visible rows
        {
          div: (l) => {
            const posts = allPosts.get(l);
            return virtualizer.getVirtualItems(l).map((item) => {
              const post = posts[item.index];
              if (!post) return { div: null, _key: item.key, style: { display: "none" } };
              return {
                div: [PostRow(post)],
                style: {
                  position: "absolute",
                  top: "0",
                  left: "0",
                  width: "100%",
                  height: `${item.size}px`,
                  transform: `translateY(${item.start}px)`,
                },
                _key: item.key,
              };
            });
          },
          style: {
            position: "relative",
            width: "100%",
            height: (l) => `${virtualizer.getTotalSize(l)}px`,
          },
        },

        // Sentinel div — when visible triggers fetchNextPage
        {
          div: null,
          _onMount: (node) => {
            const observer = new IntersectionObserver(
              (entries) => {
                if (entries[0].isIntersecting && feed.hasNextPage() && !feed.isFetchingNextPage()) {
                  feed.fetchNextPage();
                }
              },
              { threshold: 0.1 },
            );
            if (node.domElement) observer.observe(node.domElement);
            node.setMetadata("sentinelObserver", observer);
          },
          _onRemove: (node) => {
            const observer = node.getMetadata("sentinelObserver") as IntersectionObserver | undefined;
            observer?.disconnect();
          },
          style: {
            height: "1px",
            width: "100%",
          },
        },
      ],
      style: {
        height: "480px",
        overflowY: "auto",
        position: "relative",
        outline: (l) => `1px solid ${themeColor(l, "shift-4")}`,
        borderRadius: themeSpacing(2),
      },
      _onMount: (node) => virtualizer.setScrollElement(node.domElement as HTMLDivElement),
      _onRemove: () => {
        virtualizer.destroy();
        feed.destroy();
      },
    },

    // Footer: spinner while fetching next page, "Load more" button, "No more" message
    {
      div: [
        // Initial loading spinner (first load)
        {
          div: [
            { span: null, $: [spinner({ color: "primary" })] },
            {
              span: "Loading posts…",
              style: { color: (l) => themeColor(l, "shift-8") },
            },
          ],
          hidden: (l) => !feed.isPending(l),
          style: {
            display: "flex",
            alignItems: "center",
            gap: themeSpacing(2),
          },
        },

        // Fetch-next-page spinner
        {
          div: [
            { span: null, $: [spinner({ color: "primary" })] },
            {
              span: "Loading more…",
              style: { color: (l) => themeColor(l, "shift-8") },
            },
          ],
          hidden: (l) => !feed.isFetchingNextPage(l),
          style: {
            display: "flex",
            alignItems: "center",
            gap: themeSpacing(2),
          },
        },

        // Manual "Load more" fallback button
        {
          button: "Load more",
          $: [button({ color: "primary" })],
          hidden: (l) =>
            !feed.hasNextPage(l) ||
            feed.isFetchingNextPage(l) ||
            feed.isPending(l),
          onClick: () => feed.fetchNextPage(),
        },

        // End of list message
        {
          div: [{ span: "You've reached the end!", $: [paragraph()] }],
          hidden: (l) => feed.hasNextPage(l) || feed.isPending(l),
          style: {
            color: (l) => themeColor(l, "shift-7"),
            textAlign: "center",
            paddingBlock: themeSpacing(2),
          },
        },
      ],
      style: {
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        paddingBlock: themeSpacing(3),
        minHeight: themeSpacing(12),
        gap: themeSpacing(3),
      },
    },
  ],
  dataTheme: "light",
  style: {
    maxWidth: "640px",
    margin: "0 auto",
    display: "flex",
    flexDirection: "column",
    gap: "0",
    fontFamily: "system-ui, sans-serif",
  },
};

// ── Mount ────────────────────────────────────────────────────────────────────

themeApply();
new ElementNode(App).render(document.getElementById("app")!);

import { ElementNode, toState } from "@domphy/core"
import { themeApply, themeColor, themeDensity, themeSpacing } from "@domphy/theme"
import { button, card, heading, paragraph, small, spinner } from "@domphy/ui"
import { QueryClient } from "@domphy/query"
import { createInfiniteQuery } from "@domphy/query/domphy"
import { createVirtualizer } from "@domphy/virtual/domphy"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface Post {
  id: number
  title: string
  body: string
  author: string
}

interface PostPage {
  posts: Post[]
  nextPage: number | null
}

// ---------------------------------------------------------------------------
// Mock fetch: 10 posts per page
// ---------------------------------------------------------------------------

const PAGE_SIZE = 10
const TOTAL_POSTS = 100

function fetchPosts(page: number): Promise<PostPage> {
  return new Promise((resolve) => {
    setTimeout(() => {
      const start = page * PAGE_SIZE
      const posts: Post[] = Array.from({ length: PAGE_SIZE }, (_, index) => {
        const postId = start + index + 1
        return {
          id: postId,
          title: `Post #${postId}`,
          body: `This is the body of post number ${postId}. It contains some example content.`,
          author: `Author ${(postId % 5) + 1}`,
        }
      })
      const nextPage = start + PAGE_SIZE < TOTAL_POSTS ? page + 1 : null
      resolve({ posts, nextPage })
    }, 600)
  })
}

// ---------------------------------------------------------------------------
// Query client + infinite query
// ---------------------------------------------------------------------------

themeApply()

const client = new QueryClient()

const feed = createInfiniteQuery<PostPage, Error, PostPage, readonly ["posts"], number>(
  client,
  {
    queryKey: ["posts"] as const,
    queryFn: ({ pageParam }) => fetchPosts(pageParam as number),
    initialPageParam: 0,
    getNextPageParam: (lastPage) => lastPage.nextPage ?? undefined,
  },
)

// ---------------------------------------------------------------------------
// Derived flat list of all loaded posts
// ---------------------------------------------------------------------------

const allPosts = toState<Post[]>([])

feed.state.addListener(() => {
  const data = feed.data()
  if (data) {
    allPosts.set(data.pages.flatMap((page) => page.posts))
  }
})

// ---------------------------------------------------------------------------
// Virtualizer (row-based, estimated height per post card)
// ---------------------------------------------------------------------------

const ESTIMATED_ROW_HEIGHT = 120

const virtualizer = createVirtualizer<HTMLDivElement, HTMLDivElement>({
  count: 0,
  estimateSize: () => ESTIMATED_ROW_HEIGHT,
  overscan: 5,
})

// Update virtualizer count when posts list grows
allPosts.addListener(() => {
  virtualizer.setOptions({ count: allPosts.get().length })
})

// Trigger fetchNextPage when the last virtual item is near the bottom
function checkLoadMore(): void {
  const items = virtualizer.getVirtualItems()
  if (!items.length) return
  const lastItem = items[items.length - 1]
  const total = allPosts.get().length
  if (lastItem.index >= total - 3 && feed.hasNextPage() && !feed.isFetchingNextPage()) {
    feed.fetchNextPage()
  }
}

// ---------------------------------------------------------------------------
// Post card block
// ---------------------------------------------------------------------------

function PostCard(post: Post, virtualIndex: number): DomphyElement<"div"> {
  return {
    div: [
      { h3: post.title, $: [heading()] },
      { p: post.body, $: [paragraph()] },
      {
        div: [
          { small: post.author, $: [small()] },
        ],
        style: {
          display: "flex",
          alignItems: "center",
          gap: themeSpacing(2),
          paddingTop: (l) => themeSpacing(themeDensity(l) * 1),
        },
      },
    ],
    $: [card()],
    _key: post.id,
    style: {
      position: "absolute",
      top: 0,
      left: 0,
      width: "100%",
      transform: (l) => {
        virtualizer.version(l)
        const items = virtualizer.getVirtualItems()
        const item = items.find((it) => it.index === virtualIndex)
        return item ? `translateY(${item.start}px)` : "translateY(0)"
      },
      paddingBottom: themeSpacing(3),
    },
    _onMount: (node) => {
      virtualizer.measureElement(node.domElement as HTMLDivElement)
      node.domElement?.addEventListener("scroll", checkLoadMore, { passive: true })
    },
    _onRemove: (node) => {
      node.domElement?.removeEventListener("scroll", checkLoadMore)
    },
  }
}

// ---------------------------------------------------------------------------
// Spinner row
// ---------------------------------------------------------------------------

const SpinnerRow: DomphyElement<"div"> = {
  div: [
    { span: null, $: [spinner({ color: "primary" })] },
  ],
  style: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    paddingBlock: themeSpacing(6),
  },
}

// ---------------------------------------------------------------------------
// Load-more button (fallback / manual trigger)
// ---------------------------------------------------------------------------

const LoadMoreButton: DomphyElement<"div"> = {
  div: [
    {
      button: (l) => (feed.isFetchingNextPage(l) ? "Loading…" : "Load more"),
      $: [button({ color: "primary" })],
      disabled: (l) => !feed.hasNextPage(l) || feed.isFetchingNextPage(l),
      onClick: () => feed.fetchNextPage(),
    },
  ],
  style: {
    display: "flex",
    justifyContent: "center",
    paddingBlock: themeSpacing(4),
  },
}

// ---------------------------------------------------------------------------
// Virtual scroll list
// ---------------------------------------------------------------------------

const VirtualList: DomphyElement<"div"> = {
  div: (l) => {
    const items = virtualizer.getVirtualItems(l)
    const posts = allPosts.get(l)
    return items.map((item) => {
      const post = posts[item.index]
      if (!post) return null
      return PostCard(post, item.index)
    }).filter(Boolean) as DomphyElement[]
  },
  style: {
    position: "relative",
    height: (l) => `${virtualizer.getTotalSize(l)}px`,
    width: "100%",
  },
}

// ---------------------------------------------------------------------------
// Scroll container
// ---------------------------------------------------------------------------

const ScrollContainer: DomphyElement<"div"> = {
  div: [VirtualList],
  style: {
    height: "600px",
    overflowY: "auto",
    position: "relative",
  },
  _onMount: (node) => {
    virtualizer.setScrollElement(node.domElement as HTMLDivElement)
    node.domElement?.addEventListener("scroll", checkLoadMore, { passive: true })
  },
  _onRemove: (node) => {
    virtualizer.setScrollElement(null)
    node.domElement?.removeEventListener("scroll", checkLoadMore)
    virtualizer.destroy()
    feed.destroy()
  },
}

// ---------------------------------------------------------------------------
// Initial loading state
// ---------------------------------------------------------------------------

const LoadingOverlay: DomphyElement<"div"> = {
  div: [
    { span: null, $: [spinner({ color: "primary" })] },
  ],
  style: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    height: "200px",
  },
}

// ---------------------------------------------------------------------------
// Feed header
// ---------------------------------------------------------------------------

const FeedHeader: DomphyElement<"div"> = {
  div: [
    { h1: "Infinite Scroll Feed", $: [heading()] },
    { p: "Scroll down to load more posts automatically.", $: [paragraph()] },
  ],
  style: {
    paddingBlock: themeSpacing(6),
    paddingInline: themeSpacing(4),
    borderBottom: (l) => `1px solid ${themeColor(l, "shift-3", "neutral")}`,
  },
}

// ---------------------------------------------------------------------------
// Root app
// ---------------------------------------------------------------------------

const App: DomphyElement<"div"> = {
  div: [
    FeedHeader,
    {
      div: (l) => {
        const isInitialLoading = feed.isPending(l)
        if (isInitialLoading) return [LoadingOverlay]
        const isFetchingNext = feed.isFetchingNextPage(l)
        return [
          ScrollContainer,
          isFetchingNext ? SpinnerRow : LoadMoreButton,
        ]
      },
      style: {
        maxWidth: "720px",
        marginInline: "auto",
        paddingInline: themeSpacing(4),
      },
    },
  ],
  dataTheme: "light",
  style: {
    minHeight: "100vh",
    backgroundColor: (l) => themeColor(l, "inherit", "neutral"),
  },
}

// ---------------------------------------------------------------------------
// Mount
// ---------------------------------------------------------------------------

new ElementNode(App).render(document.getElementById("app")!)

import { useEffect, useRef, useCallback } from "react";
import {
  useInfiniteQuery,
  QueryClient,
  QueryClientProvider,
} from "@tanstack/react-query";

interface Post {
  id: number;
  title: string;
  body: string;
}

interface Page {
  posts: Post[];
  nextPage: number | null;
}

const POSTS_PER_PAGE = 10;
const TOTAL_POSTS = 50;

function generatePosts(page: number): Post[] {
  const start = (page - 1) * POSTS_PER_PAGE + 1;
  return Array.from({ length: POSTS_PER_PAGE }, (_, i) => ({
    id: start + i,
    title: `Post #${start + i}`,
    body: `This is the body of post ${start + i}. Lorem ipsum dolor sit amet, consectetur adipiscing elit.`,
  }));
}

async function fetchPosts(page: number): Promise<Page> {
  await new Promise((resolve) => setTimeout(resolve, 800));
  const posts = generatePosts(page);
  const totalPages = Math.ceil(TOTAL_POSTS / POSTS_PER_PAGE);
  return {
    posts,
    nextPage: page < totalPages ? page + 1 : null,
  };
}

function Feed() {
  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading,
    isError,
  } = useInfiniteQuery({
    queryKey: ["posts"],
    queryFn: ({ pageParam }) => fetchPosts(pageParam as number),
    initialPageParam: 1,
    getNextPageParam: (lastPage) => lastPage.nextPage,
  });

  const observerRef = useRef<IntersectionObserver | null>(null);

  const sentinelRef = useCallback(
    (node: HTMLDivElement | null) => {
      if (observerRef.current) {
        observerRef.current.disconnect();
      }
      if (!node) return;
      observerRef.current = new IntersectionObserver(
        (entries) => {
          if (entries[0].isIntersecting && hasNextPage && !isFetchingNextPage) {
            fetchNextPage();
          }
        },
        { threshold: 0.1 }
      );
      observerRef.current.observe(node);
    },
    [hasNextPage, isFetchingNextPage, fetchNextPage]
  );

  useEffect(() => {
    return () => {
      observerRef.current?.disconnect();
    };
  }, []);

  if (isLoading) {
    return (
      <div style={styles.center}>
        <div style={styles.spinner} />
        <p>Loading posts...</p>
      </div>
    );
  }

  if (isError) {
    return (
      <div style={styles.center}>
        <p style={{ color: "red" }}>Failed to load posts.</p>
      </div>
    );
  }

  const allPosts = data?.pages.flatMap((page) => page.posts) ?? [];

  return (
    <div style={styles.container}>
      <h1 style={styles.heading}>Infinite Scroll Feed</h1>
      <div style={styles.feed}>
        {allPosts.map((post) => (
          <div key={post.id} style={styles.card}>
            <h2 style={styles.cardTitle}>{post.title}</h2>
            <p style={styles.cardBody}>{post.body}</p>
          </div>
        ))}
      </div>
      <div ref={sentinelRef} style={styles.sentinel} />
      {isFetchingNextPage && (
        <div style={styles.center}>
          <div style={styles.spinner} />
          <p>Loading more...</p>
        </div>
      )}
      {!hasNextPage && !isLoading && (
        <p style={styles.endMessage}>You have reached the end.</p>
      )}
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  container: {
    maxWidth: 680,
    margin: "0 auto",
    padding: "24px 16px",
    fontFamily: "system-ui, sans-serif",
  },
  heading: {
    fontSize: 28,
    fontWeight: 700,
    marginBottom: 24,
    textAlign: "center",
  },
  feed: {
    display: "flex",
    flexDirection: "column",
    gap: 16,
  },
  card: {
    padding: "20px 24px",
    borderRadius: 12,
    border: "1px solid #e2e8f0",
    backgroundColor: "#ffffff",
    boxShadow: "0 1px 3px rgba(0,0,0,0.06)",
  },
  cardTitle: {
    fontSize: 18,
    fontWeight: 600,
    margin: "0 0 8px",
    color: "#1a202c",
  },
  cardBody: {
    fontSize: 14,
    color: "#4a5568",
    lineHeight: 1.6,
    margin: 0,
  },
  sentinel: {
    height: 1,
    marginTop: 24,
  },
  center: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    padding: "24px 0",
    gap: 8,
    color: "#718096",
  },
  spinner: {
    width: 32,
    height: 32,
    border: "3px solid #e2e8f0",
    borderTop: "3px solid #4299e1",
    borderRadius: "50%",
    animation: "spin 0.8s linear infinite",
  },
  endMessage: {
    textAlign: "center",
    color: "#a0aec0",
    padding: "24px 0",
    fontSize: 14,
  },
};

const queryClient = new QueryClient();

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <style>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
        * { box-sizing: border-box; }
        body { background: #f7fafc; margin: 0; }
      `}</style>
