      top: "0",
      left: "0",
      height: "100vh",
      width: themeSpacing(60),
      display: "flex",
      flexDirection: "column",
      backgroundColor: (l) => themeColor(l, "shift-1", "neutral"),
      borderRight: (l) =>
        `1px solid ${themeColor(l, "shift-4", "neutral")}`,
      overflowY: "auto",
    },
  };
}

function Header(): DomphyElement<"header"> {
  return {
    header: [
      {
        h1: (l) => {
          const path = pathname.get(l);
          const found = navItems.find((item) => item.path === path);
          return found ? found.label : "Overview";
        },
        $: [heading()],
        style: { margin: 0 },
      },
      {
        div: [
          {
            span: "3",
            $: [badge({ label: 3, color: "danger" })],
            style: {
              display: "inline-flex",
              alignItems: "center",
              justifyContent: "center",
              width: themeSpacing(9),
              height: themeSpacing(9),
              fontSize: "1.25rem",
            },
          },
          {
            span: "JD",
            $: [avatar({ color: "primary" })],
          },
          {
            div: [
              { strong: "Jane Doe", style: { fontWeight: "600" } },
              {
                small: "Admin",
                $: [small()],
              },
            ],
            style: {
              display: "flex",
              flexDirection: "column",
            },
          },
        ],
        style: {
          display: "flex",
          alignItems: "center",
          gap: themeSpacing(3),
        },
      },
    ],
    style: {
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
      padding: `${themeSpacing(4)} ${themeSpacing(6)}`,
      backgroundColor: (l) => themeColor(l, "inherit", "neutral"),
      borderBottom: (l) =>
        `1px solid ${themeColor(l, "shift-4", "neutral")}`,
      position: "sticky",
      top: "0",
      zIndex: "10",
    },
  };
}

function StatCard(stat: StatData): DomphyElement<"div"> {
  return {
    div: [
      { h3: stat.label, $: [heading()] },
      {
        p: stat.value,
        $: [paragraph()],
        style: {
          fontSize: "2rem",
          fontWeight: "700",
          margin: `${themeSpacing(1)} 0`,
        },
      },
      {
        p: stat.delta + " vs last month",
        $: [paragraph()],
        style: {
          color: (l) => themeColor(l, "shift-9", "success"),
          margin: 0,
        },
      },
    ],
    $: [card({ color: stat.color })],
    _key: stat.label,
  };
}

function OverviewPage(): DomphyElement<"div"> {
  return {
    div: [
      {
        h2: "Dashboard Overview",
        $: [heading()],
        style: { marginBottom: themeSpacing(4) },
      },
      {
        div: stats.map(StatCard),
        style: {
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
          gap: themeSpacing(4),
        },
      },
    ],
  };
}

function GenericPage(title: string, description: string): DomphyElement<"div"> {
  return {
    div: [
      { h2: title, $: [heading()] },
      { p: description, $: [paragraph()] },
    ],
  };
}

function MainContent(): DomphyElement<"main"> {
  return {
    main: [
      Header(),
      {
        div: (l) => {
          const path = pathname.get(l);
          // also read matches so reactivity re-triggers on navigation
          matches.get(l);
          switch (path) {
            case "/users":
              return [GenericPage("Users", "Manage your user accounts and permissions.")];
            case "/revenue":
              return [GenericPage("Revenue", "Track your revenue streams and financial reports.")];
            case "/orders":
              return [GenericPage("Orders", "View and manage incoming and outgoing orders.")];
            case "/settings":
              return [GenericPage("Settings", "Configure your application settings and preferences.")];
            default:
              return [OverviewPage()];
          }
        },
        style: {
          padding: themeSpacing(6),
        },
      },
    ],
    style: {
      marginLeft: themeSpacing(60),
      minHeight: "100vh",
      display: "flex",
      flexDirection: "column",
      backgroundColor: (l) => themeColor(l, "inherit", "neutral"),
    },
  };
}

// ─── App root ───────────────────────────────────────────────────────────────

const App: DomphyElement<"div"> = {
  div: [Sidebar(), MainContent()],
  dataTheme: "light",
  style: {
    fontFamily: "system-ui, sans-serif",
    minHeight: "100vh",
    backgroundColor: (l) => themeColor(l, "inherit", "neutral"),
    color: (l) => themeColor(l, "shift-9", "neutral"),
  },
};

export default App;

import { ElementNode, toState } from "@domphy/core"
import type { DomphyElement } from "@domphy/core"
import { themeApply, themeColor, themeSpacing } from "@domphy/theme"
import {
  avatar,
  badge,
  card,
  heading,
  menu,
  menuItem,
  paragraph,
  tag,
} from "@domphy/ui"
import {
  createBrowserHistory,
  createRoute,
  createRootRoute,
  createRouter,
} from "@domphy/router"

themeApply()

// --- Router setup ---

const rootRoute = createRootRoute()

const dashboardRoute = createRoute({ getParentRoute: () => rootRoute, path: "/" })
const analyticsRoute = createRoute({ getParentRoute: () => rootRoute, path: "/analytics" })
const ordersRoute    = createRoute({ getParentRoute: () => rootRoute, path: "/orders" })
const customersRoute = createRoute({ getParentRoute: () => rootRoute, path: "/customers" })
const settingsRoute  = createRoute({ getParentRoute: () => rootRoute, path: "/settings" })

const routeTree = rootRoute.addChildren([
  dashboardRoute,
  analyticsRoute,
  ordersRoute,
  customersRoute,
  settingsRoute,
])

const history = createBrowserHistory()

const router = createRouter({ routeTree, history })

// --- App state ---

const activeNav = toState<string>("dashboard")

// Sync router location -> activeNav on every resolved navigation
router.subscribe("onResolved", () => {
  const pathname = router.state.location.pathname
  const segment = pathname.replace(/^\//, "") || "dashboard"
  activeNav.set(segment)
})

// --- Nav data ---

interface NavLink {
  id: string
  label: string
  path: string
}

const navLinks: NavLink[] = [
  { id: "dashboard",  label: "Dashboard",  path: "/"           },
  { id: "analytics",  label: "Analytics",  path: "/analytics"  },
  { id: "orders",     label: "Orders",     path: "/orders"     },
  { id: "customers",  label: "Customers",  path: "/customers"  },
  { id: "settings",   label: "Settings",   path: "/settings"   },
]

// --- Stat data ---

interface StatItem {
  id: string
  label: string
  value: string
  change: string
  changeColor: "success" | "error"
}

const stats: StatItem[] = [
  { id: "users",      label: "Users",      value: "12,430", change: "+8.2%",  changeColor: "success" },
  { id: "revenue",    label: "Revenue",    value: "$94,120", change: "+5.1%", changeColor: "success" },
  { id: "orders",     label: "Orders",     value: "3,280",  change: "+12.4%", changeColor: "success" },
  { id: "conversion", label: "Conversion", value: "3.6%",   change: "-0.4%",  changeColor: "error"   },
]

// --- Blocks ---

function NavItem(link: NavLink): DomphyElement<"button"> {
  return {
    button: link.label,
    onClick: () => {
      router.navigate({ to: link.path })
    },
    $: [menuItem()],
    _key: link.id,
  }
}

function Sidebar(): DomphyElement<"nav"> {
  return {
    nav: navLinks.map(NavItem),
    // Override the overlay-default dataTone: menu() defaults to shift-17 (inverted).
    // Sidebar is a permanent surface, not an overlay — use a light surface instead.
    dataTone: "shift-1",
    $: [menu({ activeKey: activeNav, color: "neutral" })],
    style: {
      width: themeSpacing(56),
      flexShrink: 0,
      height: "100vh",
      position: "sticky",
      top: "0",
      overflowY: "auto",
    },
  }
}

function Header(): DomphyElement<"header"> {
  return {
    header: [
      { h1: "Analytics Dashboard", $: [heading()] },
      {
        div: [
          // badge() used here as a notification count pin on the avatar
          {
            span: "AJ",
            $: [
              avatar({ color: "primary" }),
              badge({ label: 3, color: "danger" }),
            ],
          },
        ],
        style: {
          display: "flex",
          alignItems: "center",
          gap: themeSpacing(3),
        },
      },
    ],
    style: {
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
      paddingBlock: themeSpacing(4),
      paddingInline: themeSpacing(6),
      borderBottom: (l) => `1px solid ${themeColor(l, "shift-3", "neutral")}`,
      backgroundColor: (l) => themeColor(l, "inherit", "neutral"),
    },
  }
}

// Stat card uses card()'s grid slots:
//   h3  -> title area (the big metric value)
//   p   -> desc area  (the label below the value)
//   aside -> aside area (the change tag, right-aligned)
function StatCard(stat: StatItem): DomphyElement<"div"> {
  return {
    div: [
      { h3: stat.value, $: [heading()] },
      { p: stat.label, $: [paragraph()] },
      {
        aside: [
          { span: stat.change, $: [tag({ color: stat.changeColor })] },
        ],
      },
    ],
    $: [card()],
    _key: stat.id,
  }
}

function StatsGrid(): DomphyElement<"section"> {
  return {
    section: stats.map(StatCard),
    style: {
      display: "grid",
      gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))",
      gap: themeSpacing(4),
      padding: themeSpacing(6),
    },
  }
}

function MainContent(): DomphyElement<"main"> {
  return {
    main: [
      Header(),
      StatsGrid(),
    ],
    style: {
      flex: "1",
      display: "flex",
      flexDirection: "column",
      overflowY: "auto",
    },
  }
}

// --- App root ---

const App: DomphyElement<"div"> = {
  div: [
    Sidebar(),
    MainContent(),
  ],
  dataTheme: "light",
  style: {
    display: "flex",
    minHeight: "100vh",
    backgroundColor: (l) => themeColor(l, "inherit", "neutral"),
  },
}

// --- Mount ---

router.load().then(() => {
  new ElementNode(App).render(document.getElementById("app")!)
})

